normalize_tw <- function(x) {
  x <- as.character(x)
  x <- gsub("\ufeff", "", x, fixed = TRUE)
  x <- trimws(x)
  x <- gsub("\\s+", "", x)
  x <- gsub("台", "臺", x)
  x
}

split_c_vector <- function(raw, numeric = FALSE) {
  raw <- gsub("[\r\n\t]", " ", raw)
  x <- strsplit(raw, ",", fixed = TRUE)[[1]]
  x <- trimws(x)
  x <- gsub("^[\\\"']|[\\\"']$", "", x)
  x <- trimws(x)
  x <- x[nzchar(x)]
  if (numeric) {
    x <- gsub(",", "", x, fixed = TRUE)
    suppressWarnings(x <- as.numeric(x))
  }
  x
}

extract_named_c_vector <- function(txt, varname) {
  pattern <- paste0(varname, "\\s*=\\s*c\\s*\\(([^()]*)\\)")
  m <- regexec(pattern, txt, perl = TRUE, ignore.case = TRUE)
  r <- regmatches(txt, m)[[1]]
  if (length(r) >= 2) r[2] else NA_character_
}

extract_all_c_vectors <- function(txt) {
  m <- gregexpr("c\\s*\\(([^()]*)\\)", txt, perl = TRUE)
  chunks <- regmatches(txt, m)[[1]]
  if (length(chunks) == 0) return(character(0))
  sub("^c\\s*\\((.*)\\)$", "\\1", chunks)
}

parse_taiwan_input <- function(txt) {
  txt <- trimws(txt)
  if (!nzchar(txt)) stop("No input data.")

  # CSV option: name,value
  csv_try <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (!inherits(csv_try, "try-error") && is.data.frame(csv_try) && ncol(csv_try) >= 2) {
    nm <- names(csv_try)
    name_col <- which(tolower(nm) %in% c("name", "county", "city", "縣市", "county_city"))[1]
    value_col <- which(tolower(nm) %in% c("value", "n", "count", "數值", "值"))[1]
    if (is.na(name_col)) name_col <- 1
    if (is.na(value_col)) value_col <- 2

    return(data.frame(
      name = csv_try[[name_col]],
      value = suppressWarnings(as.numeric(gsub(",", "", csv_try[[value_col]], fixed = TRUE))),
      stringsAsFactors = FALSE
    ))
  }

  # R-like option: name=c(...); value=c(...)
  name_raw <- extract_named_c_vector(txt, "name")
  value_raw <- extract_named_c_vector(txt, "value")

  # Fallback: first two c(...) vectors, following the old ASP split(dataaaa1, "c(") approach.
  if (is.na(name_raw) || is.na(value_raw)) {
    cvecs <- extract_all_c_vectors(txt)
    if (length(cvecs) >= 2) {
      name_raw <- cvecs[1]
      value_raw <- cvecs[2]
    }
  }

  if (is.na(name_raw) || is.na(value_raw)) {
    stop("Input must contain name=c(...) and value=c(...), or CSV with name,value.")
  }

  names_vec <- split_c_vector(name_raw, numeric = FALSE)
  values_vec <- split_c_vector(value_raw, numeric = TRUE)

  if (length(names_vec) != length(values_vec)) {
    stop(sprintf("Name count (%s) and value count (%s) are different.", length(names_vec), length(values_vec)))
  }

  data.frame(name = names_vec, value = values_vec, stringsAsFactors = FALSE)
}

validate_and_order <- function(df) {
  df$name <- normalize_tw(df$name)

  if (any(is.na(df$value))) {
    bad <- paste(df$name[is.na(df$value)], collapse = ", ")
    stop(paste("Non-numeric value detected for:", bad))
  }

  # Duplicate counties are summed, useful when pasted data has repeated rows.
  df <- aggregate(value ~ name, df, FUN = sum, na.rm = TRUE)

  required <- taiwan_asp_order$name
  missing <- setdiff(required, df$name)
  extra <- setdiff(df$name, required)

  if (length(missing) > 0 || length(extra) > 0) {
    msg <- c()
    if (length(missing) > 0) msg <- c(msg, paste("Missing:", paste(missing, collapse = ", ")))
    if (length(extra) > 0) msg <- c(msg, paste("Unknown:", paste(extra, collapse = ", ")))
    stop(paste(msg, collapse = " | "))
  }

  out <- merge(taiwan_asp_order, df, by = "name", all.x = TRUE)
  out <- out[order(out$asp_index), c("asp_index", "name", "value")]
  rownames(out) <- NULL
  out
}

compute_group_gini <- function(x, groups = 5) {
  x <- as.numeric(x)
  if (length(x) == 0 || all(is.na(x))) return(0)
  mn <- min(x, na.rm = TRUE)
  mx <- max(x, na.rm = TRUE)
  rng <- mx - mn
  if (rng == 0) return(0)

  mmrange <- rng / groups
  bin <- rep(groups, length(x))
  for (i in seq_len(groups - 1)) {
    bin[x - mn < mmrange * i] <- pmin(bin[x - mn < mmrange * i], i)
  }

  means <- tapply(x, bin, mean)
  means <- as.numeric(means[!is.na(means)])
  cluster_n2 <- length(means)
  if (cluster_n2 <= 1) return(0)

  samevalue <- sum(means)
  if (samevalue == 0) return(0)

  allvalue <- sum(abs(outer(means, means, "-")))
  round(allvalue / (2 * cluster_n2 * samevalue) / (1 - 1 / cluster_n2), 2)
}

compute_aac_top3 <- function(df) {
  x <- as.numeric(df$value)
  nm <- as.character(df$name)

  ok <- !is.na(x)
  x <- x[ok]
  nm <- nm[ok]

  if (length(x) < 3) {
    return(list(
      v1 = NA_real_, v2 = NA_real_, v3 = NA_real_,
      n1 = NA_character_, n2 = NA_character_, n3 = NA_character_,
      r = NA_real_, aac = NA_real_,
      formula = "AAC cannot be computed because fewer than three values are available."
    ))
  }

  ord <- order(x, decreasing = TRUE)
  x <- x[ord]
  nm <- nm[ord]

  v1 <- x[1]
  v2 <- x[2]
  v3 <- x[3]

  if (v2 == 0 || v3 == 0) {
    r <- NA_real_
    aac <- NA_real_
  } else {
    r <- (v1 / v2) / (v2 / v3)
    aac <- r / (1 + r)
  }

  list(
    v1 = v1, v2 = v2, v3 = v3,
    n1 = nm[1], n2 = nm[2], n3 = nm[3],
    r = round(r, 4),
    aac = round(aac, 2),
    formula = sprintf(
      "Top3: %s=%s, %s=%s, %s=%s; r=(v1/v2)/(v2/v3)=%.4f; AAC=r/(1+r)=%.2f",
      nm[1], v1, nm[2], v2, nm[3], v3, r, aac
    )
  )
}

add_asp_colors <- function(df, min_col, max_col) {
  x <- df$value
  mn <- min(x)
  mx <- max(x)
  rng <- mx - mn
  pal257 <- grDevices::colorRampPalette(c(min_col, max_col))(257)

  if (rng == 0) {
    idx <- rep(129, length(x))
  } else {
    idx <- round((x - mn) / rng * 255) + 1
    idx <- pmin(pmax(idx, 1), 257)
  }

  df$fill_color <- pal257[idx]
  df$kcolor_no_hash <- toupper(gsub("#", "", df$fill_color))
  df
}


