library(ggplot2)

data <- data.frame(
  group = c("China", "U.S", "Japan", "South K", "Germany", "Turkey", "Canada", "India", "Netherl", "Taiwan"),
  value = c(3567.59, 2590.93, 605.75, 569.81, 319.17, 253.78, 174.06, 151.54, 124.89, 103.66)
)

