    "Saint Martin" = "Saint Martin (French part)",
    "Sint Maarten" = "Sint Maarten (Dutch part)",
    "Bonaire" = "Bonaire, Sint Eustatius and Saba",
    "Sint Eustatius" = "Bonaire, Sint Eustatius and Saba",
