get_world_coord_lookup <- function() {
  coords <- utils::read.csv(text = world_coord_csv, stringsAsFactors = FALSE, check.names = FALSE)
  coords$country_geo <- normalize_world_country(coords$name)
  coords <- coords[!duplicated(coords$country_geo), c("country_geo", "latitude", "longitude")]
  coords
}

assign_cluster_colors <- function(cluster_values) {
  cl <- sort(unique(as.integer(cluster_values[!is.na(cluster_values)])))
  if (length(cl) == 0) return(character(0))
  extra_n <- max(0, length(cl) - length(specified_colors))
  extra_cols <- if (extra_n > 0) grDevices::hcl.colors(extra_n, "Dynamic") else character(0)
  pal <- c(specified_colors, extra_cols)
  map <- setNames(pal[seq_along(cl)], as.character(cl))
  unname(map[as.character(cluster_values)])
}

parse_world_input <- function(txt) {
  txt <- trimws(txt)
  if (!nzchar(txt)) stop("No world input data.")

  df <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (inherits(df, "try-error") || !is.data.frame(df) || ncol(df) < 2) {
    stop("World input must be CSV with columns Country,count, and optional cluster, latitude, longitude.")
  }

  nm <- names(df)
  nm_lower <- tolower(nm)

  country_col <- which(nm_lower %in% c("country", "name", "region", "nation"))[1]
  count_col <- which(nm_lower %in% c("count", "value", "n", "數值", "值"))[1]
  cluster_col <- which(nm_lower %in% c("cluster", "group", "class"))[1]
  lat_col <- which(nm_lower %in% c("latitude", "lat"))[1]
  lon_col <- which(nm_lower %in% c("longitude", "lng", "lon"))[1]

  if (is.na(country_col)) country_col <- 1
  if (is.na(count_col)) count_col <- 2

  out <- data.frame(
    country_original = trimws(as.character(df[[country_col]])),
    count = suppressWarnings(as.numeric(gsub(",", "", df[[count_col]], fixed = TRUE))),
    cluster = if (!is.na(cluster_col)) suppressWarnings(as.integer(df[[cluster_col]])) else NA_integer_,
    latitude = if (!is.na(lat_col)) suppressWarnings(as.numeric(df[[lat_col]])) else NA_real_,
    longitude = if (!is.na(lon_col)) suppressWarnings(as.numeric(df[[lon_col]])) else NA_real_,
    stringsAsFactors = FALSE
  )

  out <- out[nzchar(out$country_original), , drop = FALSE]

  if (any(is.na(out$count))) {
    bad <- paste(out$country_original[is.na(out$count)], collapse = ", ")
    stop(paste("Non-numeric count detected for:", bad))
  }

  out$country_geo <- normalize_world_country(out$country_original)

  # Aggregate by country and cluster when cluster is present, otherwise by country only.
  out$cluster_key <- ifelse(is.na(out$cluster), "NA", as.character(out$cluster))
  key <- if (all(is.na(out$cluster))) {
    out$country_geo
  } else {
    paste(out$country_geo, out$cluster_key, sep = "___")
  }

  parts <- split(out, key, drop = TRUE)
  agg <- do.call(rbind, lapply(parts, function(d) {
    first_non_na <- function(x) {
      idx <- which(!is.na(x) & nzchar(as.character(x)))
      if (length(idx) == 0) NA else x[idx[1]]
    }
    data.frame(
      country_original = first_non_na(d$country_original),
      country_geo = first_non_na(d$country_geo),
      count = sum(d$count, na.rm = TRUE),
      cluster = if (all(is.na(d$cluster))) NA_integer_ else as.integer(first_non_na(d$cluster)),
      latitude = suppressWarnings(as.numeric(first_non_na(d$latitude))),
      longitude = suppressWarnings(as.numeric(first_non_na(d$longitude))),
      stringsAsFactors = FALSE
    )
  }))

  agg <- as.data.frame(agg, stringsAsFactors = FALSE)
  rownames(agg) <- NULL
  agg$count <- as.numeric(agg$count)
  agg$cluster <- suppressWarnings(as.integer(agg$cluster))
  agg$latitude <- suppressWarnings(as.numeric(agg$latitude))
  agg$longitude <- suppressWarnings(as.numeric(agg$longitude))

  coords <- get_world_coord_lookup()
  agg <- merge(agg, coords, by = "country_geo", all.x = TRUE, suffixes = c("", "_lookup"))
  agg$latitude <- ifelse(is.na(agg$latitude), agg$latitude_lookup, agg$latitude)
  agg$longitude <- ifelse(is.na(agg$longitude), agg$longitude_lookup, agg$longitude)
  agg$latitude_lookup <- NULL
  agg$longitude_lookup <- NULL

  agg <- agg[order(agg$count, decreasing = TRUE), ]
  rownames(agg) <- NULL

  attr(agg, "world_mode") <- if (all(is.na(agg$cluster))) "choropleth" else "bubble"
  agg
}


parse_world_edges <- function(txt, nodes_df, enabled = TRUE) {
  if (!isTRUE(enabled)) return(data.frame())
  txt <- trimws(txt)
  if (!nzchar(txt)) return(data.frame())

  edge <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (inherits(edge, "try-error") || !is.data.frame(edge) || ncol(edge) < 3) {
    stop("World relation input must be CSV with columns term1,term2,WCD.")
  }

  nm <- tolower(names(edge))
  term1_col <- which(nm %in% c("term1", "from", "source", "node1"))[1]
  term2_col <- which(nm %in% c("term2", "terms", "to", "target", "node2"))[1]
  wcd_col <- which(nm %in% c("wcd", "weight", "value", "count", "n"))[1]

  if (is.na(term1_col)) term1_col <- 1
  if (is.na(term2_col)) term2_col <- 2
  if (is.na(wcd_col)) wcd_col <- 3

  edge <- data.frame(
    term1_original = trimws(as.character(edge[[term1_col]])),
    term2_original = trimws(as.character(edge[[term2_col]])),
    WCD = suppressWarnings(as.numeric(gsub(",", "", edge[[wcd_col]], fixed = TRUE))),
    stringsAsFactors = FALSE
  )

  edge <- edge[nzchar(edge$term1_original) & nzchar(edge$term2_original), , drop = FALSE]
  if (nrow(edge) == 0) return(data.frame())

  if (any(is.na(edge$WCD))) {
    bad <- paste(edge$term1_original[is.na(edge$WCD)], "->", edge$term2_original[is.na(edge$WCD)], collapse = ", ")
    stop(paste("Non-numeric WCD detected for:", bad))
  }

  edge$term1_geo <- normalize_world_country(edge$term1_original)
  edge$term2_geo <- normalize_world_country(edge$term2_original)

  coords <- nodes_df[, c("country_geo", "country_original", "latitude", "longitude"), drop = FALSE]
  coords <- coords[!is.na(coords$latitude) & !is.na(coords$longitude), , drop = FALSE]
  coords <- coords[!duplicated(coords$country_geo), , drop = FALSE]

  edge <- merge(edge, coords[, c("country_geo", "latitude", "longitude")],
                by.x = "term1_geo", by.y = "country_geo", all.x = TRUE)
  names(edge)[names(edge) == "latitude"] <- "lat1"
  names(edge)[names(edge) == "longitude"] <- "lon1"

  edge <- merge(edge, coords[, c("country_geo", "latitude", "longitude")],
                by.x = "term2_geo", by.y = "country_geo", all.x = TRUE)
  names(edge)[names(edge) == "latitude"] <- "lat2"
  names(edge)[names(edge) == "longitude"] <- "lon2"

  edge <- edge[!is.na(edge$lat1) & !is.na(edge$lon1) & !is.na(edge$lat2) & !is.na(edge$lon2), , drop = FALSE]
  if (nrow(edge) == 0) return(data.frame())

  mn <- min(edge$WCD, na.rm = TRUE)
  mx <- max(edge$WCD, na.rm = TRUE)
  if (mx == mn) {
    edge$line_width <- rep(3, nrow(edge))
  } else {
    edge$line_width <- round(1.2 + 6.0 * (edge$WCD - mn) / (mx - mn), 2)
  }

  edge[order(edge$WCD, decreasing = TRUE), ]
}


make_world_bubble_html <- function(df, stats, min_col = "#f1eef6", max_col = "#980043", edge_df = data.frame()) {
  missing_coords <- df$country_original[is.na(df$latitude) | is.na(df$longitude)]
  if (length(missing_coords) > 0) {
    stop(paste("Missing latitude/longitude for:", paste(missing_coords, collapse = ", ")))
  }

  df <- df[order(df$count, decreasing = TRUE), ]
  df$marker_color <- assign_cluster_colors(df$cluster)
  if (nrow(df) == 1) {
    df$marker_size <- 28
  } else {
    mn <- min(df$count, na.rm = TRUE)
    mx <- max(df$count, na.rm = TRUE)
    if (mx == mn) {
      df$marker_size <- rep(24, nrow(df))
    } else {
      df$marker_size <- round(12 + 28 * (df$count - mn) / (mx - mn), 1)
    }
  }

  rows_json <- jsonlite::toJSON(
    lapply(seq_len(nrow(df)), function(i) {
      list(
        country_original = df$country_original[i],
        country_geo = df$country_geo[i],
        count = df$count[i],
        cluster = df$cluster[i],
        latitude = df$latitude[i],
        longitude = df$longitude[i],
        marker_color = df$marker_color[i],
        marker_size = df$marker_size[i]
      )
    }),
    auto_unbox = TRUE
  )

  if (!is.data.frame(edge_df) || nrow(edge_df) == 0) {
    edge_rows <- list()
  } else {
    edge_rows <- lapply(seq_len(nrow(edge_df)), function(i) {
      list(
        term1_original = edge_df$term1_original[i],
        term2_original = edge_df$term2_original[i],
        term1_geo = edge_df$term1_geo[i],
        term2_geo = edge_df$term2_geo[i],
        WCD = edge_df$WCD[i],
        lat1 = edge_df$lat1[i],
        lon1 = edge_df$lon1[i],
        lat2 = edge_df$lat2[i],
        lon2 = edge_df$lon2[i],
        line_width = edge_df$line_width[i]
      )
    })
  }
  edge_json <- jsonlite::toJSON(edge_rows, auto_unbox = TRUE)

  top_df <- head(df[, c("country_original", "country_geo", "count", "cluster", "latitude", "longitude")], 20)
  top_rows <- paste(
    apply(top_df, 1, function(z) {
      paste0(
        "<tr><td>", htmlEscape(z[["country_original"]]), "</td>",
        "<td>", htmlEscape(z[["country_geo"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(z[["count"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(z[["cluster"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(round(as.numeric(z[["latitude"]]), 3)), "</td>",
        "<td style='text-align:right;'>", htmlEscape(round(as.numeric(z[["longitude"]]), 3)), "</td></tr>"
      )
    }),
    collapse = "\n"
  )

  if (is.data.frame(edge_df) && nrow(edge_df) > 0) {
    rel_top <- head(edge_df[, c("term1_original", "term2_original", "WCD", "line_width")], 20)
    edge_rows_html <- paste(
      apply(rel_top, 1, function(z) {
        paste0(
          "<tr><td>", htmlEscape(z[["term1_original"]]), "</td>",
          "<td>", htmlEscape(z[["term2_original"]]), "</td>",
          "<td style='text-align:right;'>", htmlEscape(z[["WCD"]]), "</td>",
          "<td style='text-align:right;'>", htmlEscape(z[["line_width"]]), "</td></tr>"
        )
      }),
      collapse = "\n"
    )
  } else {
    edge_rows_html <- "<tr><td colspan='4'>No relation curves drawn. Check the relation box and provide term1,term2,WCD while the world input contains a cluster column.</td></tr>"
  }

  note_text <- "Bubble size = count/value; bubble color = cluster. Relation curves are drawn only when the checkbox is selected and the world input contains a cluster column. Curve width is scaled by WCD. If latitude/longitude are absent, the app uses built-in country centroid coordinates. U.S and U.K are normalized to United States and United Kingdom."

  paste0(
'<!doctype html>\n',
'<html lang="en">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<script src="https://cdn.plot.ly/plotly-2.35.2.min.js"></script>\n',
'<style>\n',
'body { margin:0; font-family:Arial, sans-serif; background:#f7f7f7; color:#222; }\n',
'.wrap { padding:14px; }\n',
'.cards { display:grid; grid-template-columns:repeat(auto-fit,minmax(140px,1fr)); gap:10px; margin-bottom:12px; }\n',
'.card { background:white; border:1px solid #ddd; border-radius:8px; padding:10px 12px; box-shadow:0 1px 4px rgba(0,0,0,.08); }\n',
'.card .k { font-size:12px; color:#666; }\n',
'.card .v { font-size:20px; font-weight:bold; margin-top:3px; }\n',
'#chart { width:100%; height:680px; background:white; border:1px solid #ddd; border-radius:8px; }\n',
'table { width:100%; border-collapse:collapse; background:white; margin-top:12px; font-size:13px; }\n',
'th,td { border:1px solid #ddd; padding:6px 8px; }\n',
'th { background:#eee; text-align:left; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div class="wrap">\n',
'<h2 style="margin:0 0 10px 0;">World Bubble Dashboard</h2>\n',
'<div class="cards">\n',
'<div class="card"><div class="k">Countries/regions</div><div class="v">', stats$n, '</div></div>\n',
'<div class="card"><div class="k">Total count</div><div class="v">', stats$sum, '</div></div>\n',
'<div class="card"><div class="k">Mean</div><div class="v">', stats$mean, '</div></div>\n',
'<div class="card"><div class="k">Gini</div><div class="v">', stats$gini, '</div></div>\n',
'<div class="card"><div class="k">AAC</div><div class="v">', stats$aac_info$aac, '</div></div>\n',
'<div class="card"><div class="k">Top 1</div><div class="v" style="font-size:16px;">', htmlEscape(stats$top1), '</div></div>\n',
'</div>\n',
'<div id="chart">Loading world bubble map...</div>\n',
'<div class="card" style="margin-top:12px;"><b>AAC formula:</b> ', htmlEscape(stats$aac_info$formula), '</div>\n',
'<div class="card" style="margin-top:12px; font-size:12px; color:#555;">', htmlEscape(note_text), '</div>\n',
'<h3>Top 20 country rows</h3>\n',
'<table><thead><tr><th>Input country</th><th>Mapped country</th><th>Count</th><th>Cluster</th><th>Lat</th><th>Lon</th></tr></thead><tbody>\n',
top_rows,
'</tbody></table>\n',
'<h3>Top 20 relation rows</h3>\n',
'<table><thead><tr><th>term1</th><th>term2</th><th>WCD</th><th>Curve width</th></tr></thead><tbody>\n',
edge_rows_html,
