'</div>\n',
'<script>\n',
'const rows = ', rows_json, ';\n',
'const edgeRows = ', edge_json, ';\n',
'function curvedLine(e) {\n',
'  const steps = 36;\n',
'  const lats = [];\n',
'  const lons = [];\n',
'  const lonGap = Math.abs(e.lon2 - e.lon1);\n',
'  const latGap = Math.abs(e.lat2 - e.lat1);\n',
'  const bulge = Math.min(25, Math.max(4, (lonGap + latGap) / 10));\n',
'  for (let i = 0; i <= steps; i++) {\n',
'    const t = i / steps;\n',
'    lats.push((1 - t) * e.lat1 + t * e.lat2 + Math.sin(Math.PI * t) * bulge);\n',
'    lons.push((1 - t) * e.lon1 + t * e.lon2);\n',
'  }\n',
'  return {lat: lats, lon: lons};\n',
'}\n',
'const edgeTraces = edgeRows.map(function(e) {\n',
'  const c = curvedLine(e);\n',
'  return {\n',
'    type: "scattergeo",\n',
'    mode: "lines",\n',
'    showlegend: false,\n',
'    lat: c.lat,\n',
'    lon: c.lon,\n',
