'    line: {color: "rgba(40,40,40,0.55)", width: e.line_width}\n',
'  };\n',
'});\n',
'const clusterVals = [...new Set(rows.map(r => String(r.cluster)))];\n',
'const bubbleTraces = clusterVals.map(function(cl) {\n',
'  const sub = rows.filter(r => String(r.cluster) === cl);\n',
'  return {\n',
'    type: "scattergeo",\n',
'    mode: "markers",\n',
'    name: "Cluster " + cl,\n',
'    lat: sub.map(r => r.latitude),\n',
'    lon: sub.map(r => r.longitude),\n',
'    text: sub.map(r => "<b>" + r.country_original + "</b><br>Mapped as: " + r.country_geo + "<br>Count: " + r.count + "<br>Cluster: " + r.cluster + "<br>Lat: " + r.latitude + "<br>Lon: " + r.longitude),\n',
'    hovertemplate: "%{text}<extra></extra>",\n',
'    marker: {\n',
'      size: sub.map(r => r.marker_size),\n',
'      color: sub[0].marker_color,\n',
'      line: {color: "#333333", width: 0.8},\n',
'      opacity: 0.82\n',
'    }\n',
'  };\n',
'});\n',
'const traces = edgeTraces.concat(bubbleTraces);\n',
'const layout = {\n',
'  title: {text: "World Bubble Map by Cluster", x: 0.02},\n',
'  geo: {\n',
'    scope: "world",\n',
