'  margin: {l: 0, r: 0, t: 55, b: 0}\n',
'};\n',
'Plotly.newPlot("chart", traces, layout, {responsive: true, displaylogo: false});\n',
'</script>\n',
'</body>\n',
'</html>\n'
  )
}
compute_general_stats <- function(df, name_col = "name", value_col = "value") {
  x <- as.numeric(df[[value_col]])
  nm <- as.character(df[[name_col]])

  top1 <- paste(nm[x == max(x, na.rm = TRUE)], collapse = ", ")
  bottom1 <- paste(nm[x == min(x, na.rm = TRUE)], collapse = ", ")

  gini <- compute_group_gini(x, groups = 5)

  temp <- data.frame(name = nm, value = x, stringsAsFactors = FALSE)
  aac <- compute_aac_top3(temp)

  list(
    n = length(x),
    sum = sum(x, na.rm = TRUE),
    mean = round(mean(x, na.rm = TRUE), 2),
    min = min(x, na.rm = TRUE),
    max = max(x, na.rm = TRUE),
    gini = gini,
    aac_info = aac,
    top1 = top1,
    bottom1 = bottom1
  )
}


us_state_lookup <- data.frame(
  code = c("AL","AK","AZ","AR","CA","CO","CT","DE","FL","GA","HI","ID","IL","IN","IA","KS","KY","LA","ME","MD","MA","MI","MN","MS","MO","MT","NE","NV","NH","NJ","NM","NY","NC","ND","OH","OK","OR","PA","RI","SC","SD","TN","TX","UT","VT","VA","WA","WV","WI","WY"),
  state = c("Alabama","Alaska","Arizona","Arkansas","California","Colorado","Connecticut","Delaware","Florida","Georgia","Hawaii","Idaho","Illinois","Indiana","Iowa","Kansas","Kentucky","Louisiana","Maine","Maryland","Massachusetts","Michigan","Minnesota","Mississippi","Missouri","Montana","Nebraska","Nevada","New Hampshire","New Jersey","New Mexico","New York","North Carolina","North Dakota","Ohio","Oklahoma","Oregon","Pennsylvania","Rhode Island","South Carolina","South Dakota","Tennessee","Texas","Utah","Vermont","Virginia","Washington","West Virginia","Wisconsin","Wyoming"),
  stringsAsFactors = FALSE
)

parse_us_input <- function(txt) {
  txt <- trimws(txt)
  if (!nzchar(txt)) stop("No US input data.")

  df <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (inherits(df, "try-error") || !is.data.frame(df) || ncol(df) < 2) {
    stop("US input must be CSV with columns code,value, such as CA,16472.88.")
  }

  nm <- names(df)
  code_col <- which(tolower(nm) %in% c("code", "state_code", "abbr", "abbreviation"))[1]
  state_col <- which(tolower(nm) %in% c("state", "state_name", "name"))[1]
  value_col <- which(tolower(nm) %in% c("value", "count", "n", "total_exports", "數值", "值"))[1]

  if (is.na(code_col)) code_col <- 1
  if (is.na(value_col)) {
    numeric_cols <- which(vapply(df, function(z) suppressWarnings(all(!is.na(as.numeric(as.character(z))))), logical(1)))
    numeric_cols <- setdiff(numeric_cols, code_col)
    if (length(numeric_cols) > 0) value_col <- numeric_cols[1] else value_col <- 2
  }

  out <- data.frame(
    code = toupper(trimws(as.character(df[[code_col]]))),
    value = suppressWarnings(as.numeric(gsub(",", "", df[[value_col]], fixed = TRUE))),
    stringsAsFactors = FALSE
  )

  if (!is.na(state_col)) {
    out$state_input <- trimws(as.character(df[[state_col]]))
  }

  out <- out[nzchar(out$code), , drop = FALSE]
  out$code <- gsub("[^A-Z]", "", out$code)

  if (any(is.na(out$value))) {
    bad <- paste(out$code[is.na(out$value)], collapse = ", ")
    stop(paste("Non-numeric value detected for US state code:", bad))
  }

  # Sum duplicated state abbreviations.
  out <- aggregate(value ~ code, out, FUN = sum, na.rm = TRUE)

  unknown <- setdiff(out$code, us_state_lookup$code)
  if (length(unknown) > 0) {
    stop(paste("Unknown US state abbreviation:", paste(unknown, collapse = ", ")))
  }

  missing <- setdiff(us_state_lookup$code, out$code)
  if (length(missing) > 0) {
    stop(paste("Missing US state abbreviation(s):", paste(missing, collapse = ", ")))
  }

  out <- merge(us_state_lookup, out, by = "code", all.x = TRUE)
  out <- out[match(us_state_lookup$code, out$code), c("code", "state", "value")]
  rownames(out) <- NULL
  out
}


china_region_lookup <- data.frame(
  ord = 1:35,
  name = c("北京","天津","河北","山西","内蒙古","辽宁","吉林","黑龙江","上海","江苏","浙江","安徽","福建","江西","山东","河南","湖北","湖南","广东","广西","海南","重庆","四川","贵州","云南","西藏","陕西","甘肃","青海","宁夏","新疆","台湾","香港","澳门","南海诸岛"),
  name2 = c("Beijing","Tianjin","Hebei","Shanxi","Inner Mongolia","Liaoning","Jilin","Heilongjiang","Shanghai","Jiangsu","Zhejiang","Anhui","Fujian","Jiangxi","Shandong","Henan","Hubei","Hunan","Guangdong","Guangxi","Hainan","Chongqing","Sichuan","Guizhou","Yunnan","Tibet","Shaanxi","Gansu","Qinghai","Ningxia","Xinjiang","Taiwan","Hong Kong","Macau","South China Sea Islands"),
  stringsAsFactors = FALSE
)

normalize_china_key <- function(x) {
  y <- trimws(as.character(x))
  y <- gsub("\\s+", "", y)
  y_eng <- tolower(y)
  y_eng <- gsub("[[:space:]_\\-]+", "", y_eng)
  y_eng <- gsub("[^a-z]", "", y_eng)
  list(raw = y, eng = y_eng)
}

canonicalize_china_name <- function(x) {
  x <- trimws(as.character(x))
  key <- normalize_china_key(x)
  raw <- key$raw
  eng <- key$eng

  # direct Chinese match
  idx <- match(raw, china_region_lookup$name)
  if (!is.na(idx)) return(china_region_lookup$name[idx])

  # english aliases
  alias_map <- c(
    beijing = "北京",
    tianjin = "天津",
    hebei = "河北",
    shanxi = "山西",
    innermongolia = "内蒙古",
    inner = "内蒙古",
    liaoning = "辽宁",
    jilin = "吉林",
    heilongjiang = "黑龙江",
    shanghai = "上海",
    jiangsu = "江苏",
    zhejiang = "浙江",
    anhui = "安徽",
    fujian = "福建",
    jiangxi = "江西",
    shandong = "山东",
    henan = "河南",
    hubei = "湖北",
    hunan = "湖南",
    guangdong = "广东",
    guangxi = "广西",
    hainan = "海南",
    chongqing = "重庆",
    sichuan = "四川",
    guizhou = "贵州",
    yunnan = "云南",
    tibet = "西藏",
    xizang = "西藏",
    shaanxi = "陕西",
    gansu = "甘肃",
    qinghai = "青海",
    ningxia = "宁夏",
    xinjiang = "新疆",
    taiwan = "台湾",
    hongkong = "香港",
    hong = "香港",
    macau = "澳门",
    southchinaseaislands = "南海诸岛",
    southchinaseeislands = "南海诸岛",
    southchinaseaisland = "南海诸岛",
    southchinaseeiland = "南海诸岛"
  )

  if (eng %in% names(alias_map)) return(unname(alias_map[[eng]]))

  # maybe it matches canonical English after normalization
  cand <- tolower(china_region_lookup$name2)
  cand <- gsub("[[:space:]_\\-]+", "", cand)
  cand <- gsub("[^a-z]", "", cand)
  idx2 <- match(eng, cand)
  if (!is.na(idx2)) return(china_region_lookup$name[idx2])

  NA_character_
}

parse_china_input <- function(txt) {
  txt <- trimws(txt)
  if (!nzchar(txt)) stop("No China input data.")

  df <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (inherits(df, "try-error") || !is.data.frame(df) || ncol(df) < 2) {
    stop("China input must be CSV, e.g. name,value or region,name,name2,value.")
  }

  nm <- tolower(names(df))
  region_col <- which(nm %in% c("region"))[1]
  name_col <- which(nm %in% c("name"))[1]
  name2_col <- which(nm %in% c("name2", "english", "eng", "province_en"))[1]
  value_col <- which(nm %in% c("value", "count", "n", "數值", "值"))[1]

  if (is.na(value_col)) value_col <- ncol(df)
  if (is.na(name_col) && is.na(name2_col)) {
    # assume first column is region or name and second is value
    if (!is.na(region_col) && ncol(df) >= 2) {
      name_col <- 2
    } else {
      name_col <- 1
    }
  }

  raw_name <- rep("", nrow(df))
  if (!is.na(name_col)) raw_name <- ifelse(nzchar(trimws(as.character(df[[name_col]]))), as.character(df[[name_col]]), raw_name)
  if (!is.na(name2_col)) raw_name <- ifelse(!nzchar(trimws(raw_name)), as.character(df[[name2_col]]), raw_name)

  out <- data.frame(
    raw_name = trimws(as.character(raw_name)),
    value = suppressWarnings(as.numeric(gsub(",", "", df[[value_col]], fixed = TRUE))),
    stringsAsFactors = FALSE
  )

  if (!is.na(region_col)) {
    keep <- trimws(as.character(df[[region_col]]))
    out <- out[tolower(keep) %in% c("china", ""), , drop = FALSE]
  }

  out <- out[nzchar(out$raw_name), , drop = FALSE]
  if (any(is.na(out$value))) {
    bad <- paste(out$raw_name[is.na(out$value)], collapse = ", ")
    stop(paste("Non-numeric value detected for China region:", bad))
  }

  out$name <- vapply(out$raw_name, canonicalize_china_name, character(1))
  if (any(is.na(out$name))) {
    bad <- paste(unique(out$raw_name[is.na(out$name)]), collapse = ", ")
    stop(paste("Unknown China province/region name:", bad))
  }

  out <- aggregate(value ~ name, out[, c("name", "value")], FUN = sum, na.rm = TRUE)
  out <- merge(china_region_lookup, out, by = "name", all.x = TRUE)
  out <- out[order(out$ord), c("ord", "name", "name2", "value")]
  rownames(out) <- NULL

  missing <- out$name[is.na(out$value)]
  if (length(missing) > 0) {
    stop(paste("Missing China province/region(s):", paste(missing, collapse = ", ")))
  }

  out
}

make_china_echarts_html <- function(df, stats, min_col = "#f1eef6", max_col = "#980043") {
  map_df <- df[order(df$ord), ]
  series_data <- lapply(seq_len(nrow(map_df)), function(i) {
    list(
      name = map_df$name[i],
      value = map_df$value[i],
      english = map_df$name2[i]
    )
  })
  series_json <- jsonlite::toJSON(series_data, auto_unbox = TRUE)
  min_value <- min(map_df$value, na.rm = TRUE)
  max_value <- max(map_df$value, na.rm = TRUE)

  top_df <- head(map_df[order(map_df$value, decreasing = TRUE), c("name", "name2", "value")], 20)
  top_rows <- paste(
    apply(top_df, 1, function(z) {
      paste0(
        "<tr><td>", htmlEscape(z[["name"]]), "</td>",
        "<td>", htmlEscape(z[["name2"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(z[["value"]]), "</td></tr>"
      )
    }),
    collapse = "\n"
  )

  paste0(
'<!doctype html>\n',
'<html lang="zh-CN">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<style>\n',
'body { margin:0; font-family:Arial, sans-serif; background:#f7f7f7; color:#222; }\n',
'.wrap { padding:14px; }\n',
'.cards { display:grid; grid-template-columns:repeat(auto-fit,minmax(140px,1fr)); gap:10px; margin-bottom:12px; }\n',
'.card { background:white; border:1px solid #ddd; border-radius:8px; padding:10px 12px; box-shadow:0 1px 4px rgba(0,0,0,.08); }\n',
'.card .k { font-size:12px; color:#666; }\n',
'.card .v { font-size:20px; font-weight:bold; margin-top:3px; }\n',
'#chart { width:100%; height:640px; background:white; border:1px solid #ddd; border-radius:8px; display:flex; align-items:center; justify-content:center; color:#555; }\n',
'.map-error { padding:18px; max-width:760px; line-height:1.5; color:#8a1f11; background:#fff6f4; border:1px solid #f1b2a8; border-radius:8px; }\n',
'table { width:100%; border-collapse:collapse; background:white; margin-top:12px; font-size:13px; }\n',
'th,td { border:1px solid #ddd; padding:6px 8px; }\n',
'th { background:#eee; text-align:left; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div class="wrap">\n',
'<h2 style="margin:0 0 10px 0;">China Choropleth Dashboard</h2>\n',
'<div class="cards">\n',
'<div class="card"><div class="k">Regions</div><div class="v">', stats$n, '</div></div>\n',
'<div class="card"><div class="k">Total value</div><div class="v">', stats$sum, '</div></div>\n',
'<div class="card"><div class="k">Mean</div><div class="v">', stats$mean, '</div></div>\n',
'<div class="card"><div class="k">Gini</div><div class="v">', stats$gini, '</div></div>\n',
'<div class="card"><div class="k">AAC</div><div class="v">', stats$aac_info$aac, '</div></div>\n',
'<div class="card"><div class="k">Top 1</div><div class="v" style="font-size:16px;">', htmlEscape(stats$top1), '</div></div>\n',
'</div>\n',
'<div id="chart">Loading China map scripts...</div>\n',
'<div class="card" style="margin-top:12px;">',
'<b>AAC formula:</b> ', htmlEscape(stats$aac_info$formula),
'</div>\n',
'<div style="font-size:12px;color:#555;margin-top:6px;">Input can use Chinese names or English names, including Taiwan, Hong Kong, Macau, and 南海诸岛. If the map is blank, check whether your browser or network blocks CDN JavaScript.</div>\n',
'<h3>Top 20 regions</h3>\n',
'<table><thead><tr><th>Chinese</th><th>English</th><th>Value</th></tr></thead><tbody>\n',
top_rows,
'</tbody></table>\n',
'</div>\n',
'<script>\n',
'const chinaSeries = ', series_json, ';\n',
'const MIN_VALUE = ', min_value, ';\n',
'const MAX_VALUE = ', max_value, ';\n',
'const MIN_COLOR = "', min_col, '";\n',
'const MAX_COLOR = "', max_col, '";\n',
'const chartDiv = document.getElementById("chart");\n',
'function showMapError(msg) {\n',
'  chartDiv.innerHTML = "<div class=\\"map-error\\"><b>China map failed to load.</b><br>" + msg + "<br><br>Possible causes: CDN blocked, offline browser, or JavaScript disabled.</div>";\n',
'}\n',
'function loadScriptFallback(urls, done, fail) {\n',
'  let i = 0;\n',
'  function tryNext() {\n',
'    if (i >= urls.length) { fail(); return; }\n',
'    const url = urls[i++];\n',
'    const s = document.createElement("script");\n',
'    s.src = url;\n',
'    s.async = true;\n',
'    s.onload = done;\n',
'    s.onerror = tryNext;\n',
'    document.head.appendChild(s);\n',
'  }\n',
'  tryNext();\n',
'}\n',
'function initChinaMap() {\n',
'  try {\n',
'    if (!window.echarts) { showMapError("ECharts core library is unavailable."); return; }\n',
'    if (echarts.getMap && !echarts.getMap("china")) { showMapError("The China map definition was not registered by china.js."); return; }\n',
'    chartDiv.innerHTML = "";\n',
'    chartDiv.style.display = "block";\n',
'    const chart = echarts.init(chartDiv);\n',
'    const option = {\n',
'      tooltip: {\n',
'        trigger: "item",\n',
'        formatter: function(params) {\n',
'          const d = params.data || {};\n',
'          const en = d.english ? ("<br/>" + d.english) : "";\n',
'          const val = (d.value == null ? "NA" : d.value);\n',
'          return "<b>" + params.name + "</b>" + en + "<br/>Value: " + val;\n',
'        }\n',
'      },\n',
'      visualMap: {\n',
'        min: MIN_VALUE,\n',
'        max: MAX_VALUE,\n',
'        left: "left",\n',
'        bottom: 20,\n',
'        text: ["High", "Low"],\n',
'        calculable: true,\n',
'        inRange: { color: [MIN_COLOR, MAX_COLOR] }\n',
'      },\n',
'      series: [{\n',
'        name: "China",\n',
'        type: "map",\n',
'        mapType: "china",\n',
'        map: "china",\n',
'        roam: true,\n',
'        label: { show: false },\n',
'        emphasis: { label: { show: true, color: "#222" } },\n',
'        itemStyle: { borderColor: "#666", borderWidth: 0.8 },\n',
'        data: chinaSeries\n',
'      }]\n',
'    };\n',
'    chart.setOption(option);\n',
'    window.addEventListener("resize", function() { chart.resize(); });\n',
'  } catch(e) {\n',
'    showMapError(e.message || String(e));\n',
'  }\n',
'}\n',
'loadScriptFallback([\n',
'  "https://cdn.jsdelivr.net/npm/echarts@4.9.0/dist/echarts.min.js",\n',
'  "https://fastly.jsdelivr.net/npm/echarts@4.9.0/dist/echarts.min.js",\n',
'  "https://unpkg.com/echarts@4.9.0/dist/echarts.min.js"\n',
'], function() {\n',
'  loadScriptFallback([\n',
'    "https://cdn.jsdelivr.net/npm/echarts@4.9.0/map/js/china.js",\n',
'    "https://fastly.jsdelivr.net/npm/echarts@4.9.0/map/js/china.js",\n',
'    "https://unpkg.com/echarts@4.9.0/map/js/china.js",\n',
'    "https://assets.pyecharts.org/assets/maps/china.js"\n',
'  ], initChinaMap, function() { showMapError("All China map-script URLs failed."); });\n',
'}, function() { showMapError("All ECharts core-script URLs failed."); });\n',
'</script>\n',
'</body>\n',
'</html>\n'
  )
}

make_us_plotly_html <- function(df, stats, min_col = "#f1eef6", max_col = "#980043") {
  df <- df[match(us_state_lookup$code, df$code), ]
  map_rows <- lapply(seq_len(nrow(df)), function(i) {
    list(
      code = df$code[i],
      state = df$state[i],
      value = df$value[i],
      hover = paste0(
        "<b>", htmlEscape(df$state[i]), " (", htmlEscape(df$code[i]), ")</b>",
        "<br>Value: ", htmlEscape(df$value[i])
      )
    )
  })

  rows_json <- jsonlite::toJSON(map_rows, auto_unbox = TRUE)
  zmin <- min(df$value, na.rm = TRUE)
  zmax <- max(df$value, na.rm = TRUE)

  top_df <- head(df[order(df$value, decreasing = TRUE), c("code", "state", "value")], 20)
  top_rows <- paste(
    apply(top_df, 1, function(z) {
      paste0(
        "<tr><td>", htmlEscape(z[["code"]]), "</td>",
        "<td>", htmlEscape(z[["state"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(z[["value"]]), "</td></tr>"
      )
    }),
    collapse = "\n"
  )

  paste0(
'<!doctype html>\n',
'<html lang="en">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<script src="https://cdn.plot.ly/plotly-2.35.2.min.js"></script>\n',
'<style>\n',
'body { margin:0; font-family:Arial, sans-serif; background:#f7f7f7; color:#222; }\n',
'.wrap { padding:14px; }\n',
'.cards { display:grid; grid-template-columns:repeat(auto-fit,minmax(140px,1fr)); gap:10px; margin-bottom:12px; }\n',
'.card { background:white; border:1px solid #ddd; border-radius:8px; padding:10px 12px; box-shadow:0 1px 4px rgba(0,0,0,.08); }\n',
'.card .k { font-size:12px; color:#666; }\n',
'.card .v { font-size:20px; font-weight:bold; margin-top:3px; }\n',
'#chart { width:100%; height:620px; background:white; border:1px solid #ddd; border-radius:8px; }\n',
'table { width:100%; border-collapse:collapse; background:white; margin-top:12px; font-size:13px; }\n',
'th,td { border:1px solid #ddd; padding:6px 8px; }\n',
'th { background:#eee; text-align:left; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div class="wrap">\n',
'<h2 style="margin:0 0 10px 0;">US State Choropleth Dashboard</h2>\n',
'<div class="cards">\n',
'<div class="card"><div class="k">States</div><div class="v">', stats$n, '</div></div>\n',
'<div class="card"><div class="k">Total value</div><div class="v">', round(stats$sum, 2), '</div></div>\n',
'<div class="card"><div class="k">Mean</div><div class="v">', stats$mean, '</div></div>\n',
'<div class="card"><div class="k">Gini</div><div class="v">', stats$gini, '</div></div>\n',
'<div class="card"><div class="k">AAC</div><div class="v">', stats$aac_info$aac, '</div></div>\n',
'<div class="card"><div class="k">Top 1</div><div class="v" style="font-size:16px;">', htmlEscape(stats$top1), '</div></div>\n',
'</div>\n',
'<div id="chart">Loading US map...</div>\n',
'<div style="font-size:12px;color:#555;margin-top:6px;">Note: Alaska and Hawaii are included as lower-left insets in the Albers USA projection. Darker borders and a stronger low-end color make low-value states visible.</div>\n',
'<div class="card" style="margin-top:12px;">',
'<b>AAC formula:</b> ', htmlEscape(stats$aac_info$formula),
'</div>\n',
