'</body>\n',
'</html>\n'
  )
}


make_world_geo_html <- function(df, stats, min_col = "#f1eef6", max_col = "#980043", api_key = DEFAULT_GOOGLE_API_KEY) {
  # GeoChart receives normalized country names.
  # If several input rows map to one country/region, sum them for the map.
  map_df <- aggregate(count ~ country_geo, df, FUN = sum, na.rm = TRUE)
  originals <- aggregate(country_original ~ country_geo, df, FUN = function(z) paste(unique(z), collapse = ", "))
  map_df <- merge(map_df, originals, by = "country_geo", all.x = TRUE)
  map_df <- map_df[order(map_df$count, decreasing = TRUE), ]

  map_df$tooltip <- paste0(
    "<div style='padding:8px 10px; font:13px Arial;'>",
    "<b>", htmlEscape(map_df$country_original), "</b><br>",
    "Mapped as: ", htmlEscape(map_df$country_geo), "<br>",
    "Count: ", htmlEscape(map_df$count), "</div>"
  )

  chart_rows <- lapply(seq_len(nrow(map_df)), function(i) {
    list(map_df$country_geo[i], map_df$count[i], map_df$tooltip[i])
  })
  chart_rows_json <- jsonlite::toJSON(chart_rows, auto_unbox = TRUE)
  api_key_json <- jsonlite::toJSON(api_key, auto_unbox = TRUE)

  top_df <- head(map_df[order(map_df$count, decreasing = TRUE), c("country_original", "country_geo", "count")], 20)
  top_rows <- paste(
    apply(top_df, 1, function(z) {
      paste0(
        "<tr><td>", htmlEscape(z[["country_original"]]), "</td>",
        "<td>", htmlEscape(z[["country_geo"]]), "</td>",
        "<td style='text-align:right;'>", htmlEscape(z[["count"]]), "</td></tr>"
      )
    }),
    collapse = "\n"
  )

  paste0(
'<!doctype html>\n',
'<html lang="en">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<style>\n',
'body { margin:0; font-family:Arial, sans-serif; background:#f7f7f7; color:#222; }\n',
'.wrap { padding:14px; }\n',
'.cards { display:grid; grid-template-columns:repeat(auto-fit,minmax(140px,1fr)); gap:10px; margin-bottom:12px; }\n',
'.card { background:white; border:1px solid #ddd; border-radius:8px; padding:10px 12px; box-shadow:0 1px 4px rgba(0,0,0,.08); }\n',
'.card .k { font-size:12px; color:#666; }\n',
'.card .v { font-size:20px; font-weight:bold; margin-top:3px; }\n',
'#chart { width:100%; height:620px; background:white; border:1px solid #ddd; border-radius:8px; }\n',
'table { width:100%; border-collapse:collapse; background:white; margin-top:12px; font-size:13px; }\n',
'th,td { border:1px solid #ddd; padding:6px 8px; }\n',
'th { background:#eee; text-align:left; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div class="wrap">\n',
'<h2 style="margin:0 0 10px 0;">World Choropleth Dashboard</h2>\n',
'<div class="cards">\n',
'<div class="card"><div class="k">Countries/regions</div><div class="v">', stats$n, '</div></div>\n',
'<div class="card"><div class="k">Total count</div><div class="v">', stats$sum, '</div></div>\n',
'<div class="card"><div class="k">Mean</div><div class="v">', stats$mean, '</div></div>\n',
'<div class="card"><div class="k">Gini</div><div class="v">', stats$gini, '</div></div>\n',
'<div class="card"><div class="k">AAC</div><div class="v">', stats$aac_info$aac, '</div></div>\n',
'<div class="card"><div class="k">Top 1</div><div class="v" style="font-size:16px;">', htmlEscape(stats$top1), '</div></div>\n',
'</div>\n',
'<div id="chart">Loading world map...</div>\n',
'<div class="card" style="margin-top:12px;">',
'<b>AAC formula:</b> ', htmlEscape(stats$aac_info$formula),
'</div>\n',
'<h3>Top 20 rows</h3>\n',
'<table><thead><tr><th>Input country</th><th>Mapped country</th><th>Count</th></tr></thead><tbody>\n',
top_rows,
'</tbody></table>\n',
'</div>\n',
'<script>\n',
'const GEO_KEY = ', api_key_json, ';\n',
'let worldChartIsReady = false;\n',
'let worldChart = null;\n',
'let worldData = null;\n',
'const worldRows = ', chart_rows_json, ';\n',
'function loadGoogleCharts() {\n',
'  if (!window.google || !google.charts) {\n',
'    document.getElementById("chart").innerHTML = "Google Charts loader failed. Check internet access or browser blocking.";\n',
'    return;\n',
'  }\n',
'  google.charts.load("current", {"packages":["geochart"], "mapsApiKey": GEO_KEY});\n',
'  google.charts.setOnLoadCallback(drawRegionsMap);\n',
'}\n',
'function drawRegionsMap() {\n',
'  worldData = new google.visualization.DataTable();\n',
'  worldData.addColumn("string", "Country");\n',
'  worldData.addColumn("number", "Count");\n',
'  worldData.addColumn({"type":"string", "role":"tooltip", "p":{"html":true}});\n',
'  worldData.addRows(worldRows);\n',
'  const options = {\n',
'    region: "world",\n',
'    displayMode: "regions",\n',
'    resolution: "countries",\n',
'    backgroundColor: "#f7f7f7",\n',
'    datalessRegionColor: "#eeeeee",\n',
'    colorAxis: {colors: ["', min_col, '", "', max_col, '"]},\n',
'    tooltip: {trigger: "focus", isHtml: true},\n',
'    legend: {textStyle: {fontSize: 12}}\n',
'  };\n',
'  worldChart = new google.visualization.GeoChart(document.getElementById("chart"));\n',
'  worldChart.draw(worldData, options);\n',
'  worldChartIsReady = true;\n',
'}\n',
'window.addEventListener("resize", function() { if (worldChartIsReady) drawRegionsMap(); });\n',
'const loader = document.createElement("script");\n',
'loader.src = "https://www.gstatic.com/charts/loader.js";\n',
'loader.async = true;\n',
'loader.onload = loadGoogleCharts;\n',
'loader.onerror = function() { document.getElementById("chart").innerHTML = "Google Charts script failed to load."; };\n',
'document.head.appendChild(loader);\n',
'</script>\n',
'</body>\n',
'</html>\n'
  )
}


make_google_map_html <- function(df, api_key, polygon_json) {
  # JSON for the 22 value/color records, keyed by ASP zero-based index.
  county_data <- df[order(df$asp_index), c("asp_index", "name", "value", "fill_color")]
  county_data_json <- jsonlite::toJSON(county_data, dataframe = "rows", auto_unbox = TRUE)
  api_key_json <- jsonlite::toJSON(api_key, auto_unbox = TRUE)

  paste0(
'<!doctype html>\n',
'<html lang="zh-TW">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<style>\n',
'html, body, #map { height: 100%; width: 100%; margin: 0; padding: 0; font-family:Arial, sans-serif; }\n',
'.legend { position:absolute; right:14px; bottom:26px; background:white; padding:10px 12px; border:1px solid #777; font:12px Arial, sans-serif; box-shadow:0 1px 4px rgba(0,0,0,.25); z-index:5; border-radius:6px; }\n',
'.swatch { display:inline-block; width:14px; height:14px; border:1px solid #555; margin-right:6px; vertical-align:middle; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div id="map"></div>\n',
'<div id="status" style="display:none;">Loading Google Taiwan map...</div>\n',
'<div class="legend">',
'<div><span class="swatch" style="background:', df$fill_color[which.min(df$value)][1], '"></span>Min: ', htmlEscape(as.character(min(df$value))), '</div>',
'<div><span class="swatch" style="background:', df$fill_color[which.max(df$value)][1], '"></span>Max: ', htmlEscape(as.character(max(df$value))), '</div>',
'</div>\n',
'<script>\n',
'var google_api_key = ', api_key_json, ';\n',
'const API_KEY = google_api_key;\n',
'const polygons = ', polygon_json, ';\n',
'const rows = ', county_data_json, ';\n',
'const countyData = {};\n',
'rows.forEach(function(r) { countyData[r.asp_index] = r; });\n',
'function initMap() {\n',
'  const map = new google.maps.Map(document.getElementById("map"), {\n',
'    center: {lat: 23.8, lng: 121.0},\n',
'    zoom: 7,\n',
'    mapTypeId: "terrain",\n',
'    streetViewControl: false,\n',
'    fullscreenControl: true\n',
'  });\n',
'  const info = new google.maps.InfoWindow();\n',
'  let drawn = 0;\n',
'  polygons.forEach(function(poly) {\n',
'    const d = countyData[poly.index];\n',
'    if (!d) return;\n',
'    const path = poly.points.map(function(p) { return {lat:p[0], lng:p[1]}; });\n',
'    const gpoly = new google.maps.Polygon({\n',
'      paths: path,\n',
'      strokeColor: "#000000",\n',
'      strokeOpacity: 0.75,\n',
'      strokeWeight: 1,\n',
'      fillColor: d.fill_color,\n',
'      fillOpacity: 0.85,\n',
'      clickable: true\n',
'    });\n',
'    gpoly.setMap(map);\n',
'    drawn += 1;\n',
'    const hoverHtml = "<strong>" + poly.county + "</strong><br>Value: " + d.value + "<br>Color: " + d.fill_color + "<br>ASP track: " + poly.track;\n',
'    gpoly.addListener("mouseover", function(e) {\n',
'      gpoly.setOptions({strokeWeight:3, fillOpacity:0.96});\n',
'      info.setContent(hoverHtml);\n',
'      info.setPosition(e.latLng);\n',
'      info.open(map);\n',
'    });\n',
'    gpoly.addListener("mousemove", function(e) { info.setPosition(e.latLng); });\n',
'    gpoly.addListener("mouseout", function() { gpoly.setOptions({strokeWeight:1, fillOpacity:0.85}); });\n',
'    gpoly.addListener("click", function(e) {\n',
'      info.setContent(hoverHtml);\n',
'      info.setPosition(e.latLng);\n',
'      info.open(map);\n',
'    });\n',
'  });\n',
'  document.getElementById("status").innerHTML = "Loaded: " + drawn + " ASP polygon tracks.";\n',
'}\n',
'function mapLoadError() {\n',
'  const el = document.getElementById("status");\n',
'  el.style.display = "block";\n',
'  el.style.position = "absolute";\n',
'  el.style.left = "12px";\n',
'  el.style.top = "12px";\n',
'  el.style.zIndex = "9999";\n',
'  el.style.background = "white";\n',
'  el.style.padding = "8px";\n',
'  el.style.border = "1px solid #777";\n',
'  el.innerHTML = "Google Maps failed to load. Check the API key, billing, domain restriction, and Maps JavaScript API setting.";\n',
'}\n',
'const s = document.createElement("script");\n',
's.src = "https://maps.googleapis.com/maps/api/js?key=" + encodeURIComponent(API_KEY) + "&callback=initMap&language=zh-TW";\n',
's.async = true;\n',
's.defer = true;\n',
's.onerror = mapLoadError;\n',
'document.head.appendChild(s);\n',
'</script>\n',
'</body>\n',
'</html>\n'
  )
}

