parse_plot_input <- function(txt) {
  txt <- trimws(txt)
  if (!nzchar(txt)) stop("No plot input data.")

  df <- try(utils::read.csv(
    text = txt,
    stringsAsFactors = FALSE,
    check.names = FALSE
  ), silent = TRUE)

  if (inherits(df, "try-error") || !is.data.frame(df) || ncol(df) < 2) {
    stop("Plot input must be CSV with at least two columns.")
  }

  df
}

html_escape2 <- function(x) {
  x <- paste(as.character(x), collapse = "\n")
  x <- gsub("&", "&amp;", x, fixed = TRUE)
  x <- gsub("<", "&lt;", x, fixed = TRUE)
  x <- gsub(">", "&gt;", x, fixed = TRUE)
  x
}


extract_pasted_r_packages <- function(code) {
  code <- paste(as.character(code), collapse = "\n")
  pkgs <- character(0)

  # Detect common forms:
  # library(ggplot2), library("ggplot2"), require(dplyr), require("dplyr")
  lib_matches <- gregexpr("\\b(?:library|require)\\s*\\(\\s*['\\\"]?([A-Za-z][A-Za-z0-9._]*)['\\\"]?", code, perl = TRUE)
  if (lib_matches[[1]][1] != -1) {
    hits <- regmatches(code, lib_matches)[[1]]
    pkgs <- c(pkgs, sub(".*\\(\\s*['\\\"]?([A-Za-z][A-Za-z0-9._]*).*", "\\1", hits, perl = TRUE))
  }

  # Detect pacman::p_load(pkg1, pkg2, "pkg3")
  p_load_matches <- gregexpr("pacman::p_load\\s*\\(([^\\)]*)\\)", code, perl = TRUE)
  if (p_load_matches[[1]][1] != -1) {
    hits <- regmatches(code, p_load_matches)[[1]]
    inside <- gsub("^pacman::p_load\\s*\\((.*)\\)$", "\\1", hits, perl = TRUE)
    for (x in inside) {
      parts <- unlist(strsplit(x, ","))
      parts <- trimws(gsub("['\\\"]", "", parts))
      parts <- parts[grepl("^[A-Za-z][A-Za-z0-9._]*$", parts)]
      pkgs <- c(pkgs, parts)
    }
  }

  unique(pkgs[nzchar(pkgs)])
}

# Note: runtime package installation may fail on shinyapps.io.
# For stable deployment, add frequently used packages to app_shinyio_dependency_candidates
# or to the deployment helper script included with this ZIP.
install_missing_pasted_r_packages <- function(code) {
  pkgs <- extract_pasted_r_packages(code)
  pkgs <- setdiff(pkgs, c("base", "stats", "graphics", "grDevices", "utils", "methods", "datasets"))

  if (length(pkgs) == 0) {
    return(character(0))
  }

  missing <- pkgs[
    !vapply(pkgs, requireNamespace, logical(1), quietly = TRUE)
  ]

  if (length(missing) > 0) {
    install.packages(missing, repos = "https://cloud.r-project.org")
  }

  missing_after <- missing[
    !vapply(missing, requireNamespace, logical(1), quietly = TRUE)
  ]

  if (length(missing_after) > 0) {
    stop(
      "These packages were requested by the pasted R script but could not be installed: ",
      paste(missing_after, collapse = ", "),
      ". Add them to app_required_packages in app.R before deployment, or install them manually."
    )
  }

  missing
}


app_bold_ggplot_theme <- function(base_size = 20) {
  ggplot2::theme(
    text = ggplot2::element_text(size = base_size, face = "bold"),
    plot.title = ggplot2::element_text(size = base_size + 6, face = "bold", hjust = 0.5),
    plot.subtitle = ggplot2::element_text(size = base_size + 2, face = "bold"),
    axis.title = ggplot2::element_text(size = base_size + 2, face = "bold"),
    axis.text = ggplot2::element_text(size = base_size, face = "bold"),
    axis.text.x = ggplot2::element_text(size = base_size, face = "bold"),
    axis.text.y = ggplot2::element_text(size = base_size, face = "bold"),
    legend.title = ggplot2::element_text(size = base_size + 1, face = "bold"),
    legend.text = ggplot2::element_text(size = base_size, face = "bold"),
    strip.text = ggplot2::element_text(size = base_size, face = "bold")
  )
}

app_make_bold_ggplot <- function(p, base_size = 20) {
  if (inherits(p, "ggplot")) {
    p + app_bold_ggplot_theme(base_size = base_size)
  } else {
    p
  }
}


app_prepare_custom_r_code <- function(code) {
  code <- paste(as.character(code), collapse = "\n")

  # WrightMap fix:
  # wrightMap(..., new.quartz=TRUE) opens a separate graphics device.
  # In Shiny custom plotting mode, the app already opens a PNG device.
  # If WrightMap opens a new quartz device, the PNG remains blank/unfinished.
  # Therefore force WrightMap to draw on the current app PNG device.
  code <- gsub(
    "new\\.quartz\\s*=\\s*TRUE",
    "new.quartz = FALSE",
    code,
    ignore.case = TRUE,
    perl = TRUE
  )
  code <- gsub(
    "new\\.quartz\\s*=\\s*T\\b",
    "new.quartz = FALSE",
    code,
    ignore.case = TRUE,
    perl = TRUE
  )

  # Avoid closing the app PNG device from inside pasted scripts before the app can capture it.
  # The app closes graphics devices safely after evaluation.
  code <- gsub(
    "^\\s*dev\\.off\\s*\\(\\s*\\)\\s*$",
    "# dev.off() removed by App4htmlVisualinR custom plot capture",
    code,
    perl = TRUE
  )

  # Make common ggplot complete themes respect the Custom R font-size box.
  # This handles theme_classic(), theme_minimal(), theme_bw(), etc. when no arguments are supplied.
  theme_funs <- c(
    "theme_classic", "theme_minimal", "theme_bw", "theme_gray",
    "theme_light", "theme_dark", "theme_void"
  )
  for (fn in theme_funs) {
    code <- gsub(
      paste0("\\b", fn, "\\s*\\(\\s*\\)"),
      paste0(fn, "(base_size = font_size)"),
      code,
      perl = TRUE
    )
  }

  # Critical fix:
  # Many pasted scripts call print(p) inside the code. In that case the plot is drawn
  # before App4htmlVisualinR can add the bold font theme afterward.
  # Rewrite simple print(object_name) calls so the app font-size control is applied immediately.
  code <- gsub(
    "\\bprint\\s*\\(\\s*([A-Za-z.][A-Za-z0-9._]*)\\s*\\)",
    "print(app_make_bold_ggplot(\\1, base_size = font_size))",
    code,
    perl = TRUE
  )

  code
}


app_safe_cocMatrix <- function(...) {
  if (!requireNamespace("bibliometrix", quietly = TRUE)) {
    stop("Package bibliometrix is required for cocMatrix().")
  }

  out <- bibliometrix::cocMatrix(...)

  if (is.matrix(out) || inherits(out, "Matrix")) {
    return(out)
  }

  # Some bibliometrix fields can return a data.frame/tibble/vector-like object
  # instead of a base matrix. Coerce when possible so colSums() and matrix checks work.
  if (inherits(out, "data.frame")) {
    return(as.matrix(out))
  }

  if (is.atomic(out) && !is.null(out)) {
    return(as.matrix(out))
  }

  if (is.list(out)) {
    for (x in out) {
      if (is.matrix(x) || inherits(x, "Matrix")) return(x)
      if (inherits(x, "data.frame")) return(as.matrix(x))
      if (is.atomic(x) && !is.null(x)) return(as.matrix(x))
    }
  }

  warning("cocMatrix() did not return a matrix-like object; returning an empty matrix.")
  matrix(numeric(0), nrow = 0, ncol = 0)
}

make_custom_r_plot_html <- function(code, font_size = 22) {
  if (is.null(code)) code <- ""
  code <- trimws(as.character(code))
  font_size <- suppressWarnings(as.numeric(font_size))
  if (is.na(font_size) || font_size <= 0) font_size <- 22
  font_size <- max(8, min(60, font_size))

  if (!nzchar(code)) {
    return('<div class="note"><b>Custom R plot skipped:</b> no R code was supplied.</div>')
  }

  if (!requireNamespace("base64enc", quietly = TRUE)) {
    return('<div class="note"><b>Custom R plot error:</b> package base64enc is required to embed the generated PNG. Please install/deploy with install.packages(c(&quot;base64enc&quot;, &quot;ggplot2&quot;)).</div>')
  }

  run_custom_code_once <- function(code, png_file, width, height, res, margin_mode = "safe", font_size = 22) {
    env <- new.env(parent = globalenv())

    # Standalone mode:
    # The pasted R script should define its own data when needed.
    # Empty placeholders are provided only to avoid object-not-found errors.
    env$data <- data.frame()
    env$df <- data.frame()
    env$plot_data <- data.frame()
    env$input_data <- data.frame()
    env$font_size <- font_size
    env$app_make_bold_ggplot <- app_make_bold_ggplot
    env$app_bold_ggplot_theme <- app_bold_ggplot_theme
    env$cocMatrix <- app_safe_cocMatrix

    console <- character(0)
    installed_from_script <- character(0)
    final_value <- NULL
    err_msg <- NULL

    tryCatch({
      installed_from_script <- install_missing_pasted_r_packages(code)

      original_dev <- grDevices::dev.cur()
      grDevices::png(filename = png_file, width = width, height = height, res = res)
      png_dev <- grDevices::dev.cur()

      old_par <- graphics::par(no.readonly = TRUE)
      on.exit({
        try(graphics::par(old_par), silent = TRUE)
      }, add = TRUE)

      base_cex <- max(0.7, min(2.5, font_size / 14))
      axis_cex <- max(0.7, min(2.8, font_size / 13))
      lab_cex <- max(0.8, min(3.0, font_size / 12))
      main_cex <- max(0.9, min(3.2, font_size / 11))

      if (identical(margin_mode, "ultra")) {
        graphics::par(
          mfrow = c(1, 1),
          mar = c(4.5, 7.0, 2.5, 0.8),
          oma = c(0, 0, 0, 0),
          mgp = c(2.3, 0.7, 0),
          xaxs = "i",
          yaxs = "i",
          cex.axis = axis_cex,
          cex.lab = lab_cex,
          cex.main = main_cex,
          font.axis = 2,
          font.lab = 2,
          font.main = 2
        )
      } else {
        graphics::par(
          mfrow = c(1, 1),
          mar = c(5.2, 7.8, 3.5, 1.2),
          oma = c(0, 0, 0, 0),
          mgp = c(2.6, 0.8, 0),
          cex.axis = axis_cex,
          cex.lab = lab_cex,
          cex.main = main_cex,
          font.axis = 2,
          font.lab = 2,
          font.main = 2
        )
      }

      prepared_code <- app_prepare_custom_r_code(code)
      exprs <- parse(text = prepared_code)
      console <- utils::capture.output({
        last_value <- NULL
        for (expr in exprs) {
          # Reset base-graphics layout before every expression. This prevents
          # a previous par(mfrow=...), par(mar=...), or layout() call from
          # shrinking the next plotting region and causing margin errors.
          if (identical(margin_mode, "ultra")) {
            graphics::par(
              mfrow = c(1, 1),
              mar = c(4.5, 7.0, 2.5, 0.8),
              oma = c(0, 0, 0, 0),
              mgp = c(2.3, 0.7, 0),
              xaxs = "i",
              yaxs = "i",
              cex.axis = axis_cex,
              cex.lab = lab_cex,
              cex.main = main_cex,
              font.axis = 2,
              font.lab = 2,
              font.main = 2
            )
          } else {
            graphics::par(
              mfrow = c(1, 1),
              mar = c(3.5, 3.5, 2.2, 0.8),
              oma = c(0, 0, 0, 0),
              mgp = c(2.0, 0.6, 0)
            )
          }

          last_value <- eval(expr, envir = env)
          final_value <- last_value

          if (inherits(last_value, "ggplot")) {
            print(app_make_bold_ggplot(last_value, base_size = font_size))
          } else if (inherits(last_value, "recordedplot")) {
            replayPlot(last_value)
          }
        }

        if (exists("p", envir = env, inherits = FALSE) && inherits(get("p", envir = env), "ggplot")) {
          final_value <- get("p", envir = env)
          print(get("p", envir = env))
        }
        if (exists("plot", envir = env, inherits = FALSE) && inherits(get("plot", envir = env), "ggplot")) {
          final_value <- get("plot", envir = env)
          print(get("plot", envir = env))
        }
      })
    }, error = function(e) {
      err_msg <<- conditionMessage(e)
    }, finally = {
      # Close all graphics devices opened during pasted-script evaluation, including
      # accidental extra devices opened by functions such as WrightMap/new.quartz.
      # This ensures the app PNG device is closed and the file is written.
      try({
        while (grDevices::dev.cur() > 1) {
          grDevices::dev.off()
        }
      }, silent = TRUE)
    })

    list(
      error = err_msg,
      console = console,
      installed = installed_from_script,
      file = png_file,
      width = width,
      height = height,
      res = res,
      margin_mode = margin_mode,
      value = final_value
    )
  }

  png_file <- tempfile(fileext = ".png")

  # First attempt: large device.
  result <- run_custom_code_once(
    code = code,
    png_file = png_file,
    width = 1600,
    height = 1100,
    res = 96,
    margin_mode = "safe",
    font_size = font_size
  )

  # Second attempt: automatic rescue for "figure margins too large".
  # This is especially useful for base R plots with layout/mfrow/mar settings.
  retried_margin <- FALSE
  if (!is.null(result$error) && grepl("figure margins too large", result$error, ignore.case = TRUE)) {
    retried_margin <- TRUE
    png_file <- tempfile(fileext = ".png")
    result <- run_custom_code_once(
      code = code,
      png_file = png_file,
      width = 2400,
      height = 1800,
      res = 96,
      margin_mode = "ultra",
      font_size = font_size
    )
  }

  err_msg <- result$error
  console <- result$console
  installed_from_script <- result$installed
  png_file <- result$file

  if (!is.null(err_msg)) {
    hint <- ""
    if (grepl("figure margins too large", err_msg, ignore.case = TRUE)) {
      hint <- paste0(
        "<br><b>Hint:</b> The pasted script is still shrinking the plotting region, ",
        "usually through <code>par(mfrow=...)</code>, <code>par(mar=...)</code>, ",
        "<code>layout()</code>, or very long labels. ",
        "Please remove those settings from the pasted script or add ",
        "<code>par(mfrow=c(1,1), mar=c(2,2,1,0.5), oma=c(0,0,0,0))</code> ",
        "immediately before the base R plotting command. For ggplot2 scripts, avoid calling base <code>plot()</code> after <code>print(p)</code>."
      )
    }
    if (grepl("The object 'A' is not a matrix|not a matrix", err_msg, ignore.case = TRUE)) {
      hint <- paste0(
        hint,
        "<br><b>Hint:</b> In bibliometrix, some <code>cocMatrix()</code> fields may not return a base matrix. ",
        "The app now provides a safe <code>cocMatrix()</code> wrapper that tries to coerce outputs to a matrix. ",
        "You can also replace <code>stop(\"The object 'A' is not a matrix.\")</code> with <code>A &lt;- as.matrix(A)</code> when possible, ",
        "or use frequency tables for single fields such as <code>SO</code>."
      )
    }

    partial_html <- ""
    if (file.exists(png_file) && !is.na(file.info(png_file)$size) && file.info(png_file)$size > 0) {
      partial_src <- base64enc::dataURI(file = png_file, mime = "image/png")
      partial_html <- paste0(
        '<div class="note"><b>Partial plot captured before the error</b><br>',
        'The pasted script generated a plot before stopping. The image is shown below.</div>',
        '<div class="chartBox" style="min-height:auto; padding:10px;">',
        '<img src="', partial_src, '" style="max-width:100%; height:auto; display:block; margin:auto;" />',
        '</div>'
      )
    }

    return(paste0(
      '<div class="note"><b>Custom R plot error:</b><br><pre style="white-space:pre-wrap;">',
      html_escape2(err_msg),
      '</pre>',
      hint,
      '</div>',
      partial_html
    ))
  }

  widget_value <- result$value
  if (!is.null(widget_value) && inherits(widget_value, "htmlwidget")) {
    widget_file <- tempfile(fileext = ".html")
    widget_err <- NULL
    tryCatch({
      htmlwidgets::saveWidget(widget_value, file = widget_file, selfcontained = TRUE)
    }, error = function(e) {
      widget_err <<- conditionMessage(e)
    })

    if (is.null(widget_err) && file.exists(widget_file) && file.info(widget_file)$size > 0) {
      widget_src <- base64enc::dataURI(file = widget_file, mime = "text/html")
      console_html <- if (length(console)) {
        paste0(
          '<details class="note"><summary>Custom R console output</summary><pre style="white-space:pre-wrap;">',
          html_escape2(console),
          '</pre></details>'
        )
      } else {
        ""
      }
      pkg_html <- if (length(installed_from_script)) {
        paste0(
          '<br><b>Auto-installed packages from pasted script:</b> ',
          html_escape2(paste(installed_from_script, collapse = ", "))
        )
      } else {
        ""
      }
      return(paste0(
        '<div class="note"><b>Custom R htmlwidget</b><br>',
        'The pasted R script returned an htmlwidget object. It was saved as standalone HTML and embedded below.',
        pkg_html,
        '</div>',
        '<iframe src="', widget_src, '" style="width:100%; height:760px; border:1px solid #ddd; border-radius:8px; background:rgba(255,255,255,0);" loading="lazy"></iframe>',
        console_html
      ))
    }
  }

  if (!file.exists(png_file) || is.na(file.info(png_file)$size) || file.info(png_file)$size <= 0) {
    return('<div class="note"><b>Custom R plot warning:</b> code ran, but no image file was generated. Use print(p), return a ggplot object, or ensure base plotting functions draw on the current device. For WrightMap, use new.quartz=FALSE; App4htmlVisualinR now rewrites new.quartz=TRUE to FALSE automatically.</div>')
  }

  img_src <- base64enc::dataURI(file = png_file, mime = "image/png")
  console_html <- if (length(console)) {
    paste0(
      '<details class="note"><summary>Custom R console output</summary><pre style="white-space:pre-wrap;">',
      html_escape2(console),
      '</pre></details>'
    )
  } else {
    ""
  }

  pkg_html <- if (length(installed_from_script)) {
    paste0(
      '<br><b>Auto-installed packages from pasted script:</b> ',
      html_escape2(paste(installed_from_script, collapse = ", "))
    )
  } else {
    ""
  }

  retry_html <- if (isTRUE(retried_margin)) {
    '<br><b>Margin rescue:</b> The first plot attempt reported figure margins too large, so the app automatically retried using an ultra-large device and compact margins.'
  } else {
    ""
  }

  paste0(
    '<div class="note"><b>Custom R plot</b><br>',
    'The pasted R script was executed independently. The CSV input box above was ignored. Put data creation and plotting code directly inside the R script box.',
    pkg_html,
    retry_html,
    '</div>',
    '<div class="chartBox" style="min-height:auto; padding:10px;">',
    '<img src="', img_src, '" style="max-width:100%; height:auto; display:block; margin:auto;" />',
    '</div>',
    console_html
  )
}

insert_custom_fragment <- function(html, custom_fragment) {
  if (is.null(custom_fragment)) custom_fragment <- ""
  custom_fragment <- as.character(custom_fragment)
  if (!nzchar(custom_fragment)) return(html)

  target <- '<div id="charts"></div>\n'
  if (grepl(target, html, fixed = TRUE)) {
    return(sub(target, paste0(target, custom_fragment, "\n"), html, fixed = TRUE))
  }

  sub("</body>", paste0(custom_fragment, "\n</body>"), html, fixed = TRUE)
}

make_plots_html <- function(df, selected) {
  selected <- selected[!is.na(selected)]
  if (length(selected) == 0) selected <- character(0)

  rows_json <- jsonlite::toJSON(df, dataframe = "rows", auto_unbox = TRUE, na = "null")
  cols_json <- jsonlite::toJSON(names(df), auto_unbox = TRUE)
  selected_json <- jsonlite::toJSON(selected, auto_unbox = TRUE)

  paste0(
'<!doctype html>\n',
'<html lang="en">\n',
'<head>\n',
'<meta charset="utf-8"/>\n',
'<meta name="viewport" content="width=device-width, initial-scale=1.0"/>\n',
'<script src="https://cdn.plot.ly/plotly-2.35.2.min.js"></script>\n',
'<script src="https://d3js.org/d3.v7.min.js"></script>\n',
'<style>\n',
'html, body { margin:0; padding:0; background:rgba(255,255,255,0); font-family:Arial, sans-serif; color:#222; }\n',
'.wrap { padding:14px; background:rgba(255,255,255,0); }\n',
'.note { background:rgba(255,255,255,.86); border:1px solid #ddd; border-radius:8px; padding:10px 12px; margin-bottom:12px; font-size:13px; }\n',
'.chartBox { width:100%; min-height:520px; margin:14px 0 24px 0; border:1px solid #ddd; border-radius:8px; background:rgba(255,255,255,0); }\n',
'.svgWrap { width:100%; height:720px; }\n',
'h2, h3 { margin: 6px 0 8px 0; }\n',
'</style>\n',
'</head>\n',
'<body>\n',
'<div class="wrap">\n',
'<h2>Additional Plot Dashboard</h2>\n',
'<div class="note">Background transparency is set to 0 using transparent Plotly paper and plot backgrounds. Full CSV input formats for all Additional plots have been moved to the ReadMe tab.</div>\n',
'<div id="charts"></div>\n',
'</div>\n',
'<script>\n',
'const rows = ', rows_json, ';\n',
'const cols = ', cols_json, ';\n',
'const selected = ', selected_json, ';\n',
'const root = document.getElementById("charts");\n',
'const fixedColors = ["#FF0000","#0000FF","#FFFF00","#008000","#800080","#FFC0CB","#000000","#ADD8E6"];\n',
'function isNum(v) { return v !== null && v !== undefined && v !== "" && !isNaN(Number(String(v).replace(/,/g, ""))); }\n',
'function num(v) { return Number(String(v).replace(/,/g, "")); }\n',
'function lower(s) { return String(s || "").trim().toLowerCase(); }\n',
'function colBy(candidates) {\n',
'  const lc = cols.map(c => lower(c));\n',
'  for (const cand of candidates) {\n',
'    const idx = lc.indexOf(lower(cand));\n',
'    if (idx >= 0) return cols[idx];\n',
'  }\n',
'  return null;\n',
'}\n',
'function numericCols() {\n',
'  return cols.filter(c => rows.length > 0 && rows.every(r => isNum(r[c])));\n',
'}\n',
'function firstTextCol() {\n',
'  const ncs = new Set(numericCols());\n',
'  return cols.find(c => !ncs.has(c)) || cols[0];\n',
'}\n',
'function newDiv(title, svgMode=false) {\n',
'  const h = document.createElement("h3");\n',
'  h.textContent = title;\n',
'  root.appendChild(h);\n',
'  const d = document.createElement("div");\n',
'  d.className = "chartBox";\n',
'  if (svgMode) d.classList.add("svgWrap");\n',
'  root.appendChild(d);\n',
'  return d;\n',
'}\n',
'function transparentLayout(title) {\n',
'  return {\n',
'    title: {text: title, x: 0.02},\n',
'    paper_bgcolor: "rgba(255,255,255,0)",\n',
'    plot_bgcolor: "rgba(255,255,255,0)",\n',
'    margin: {l: 70, r: 35, t: 55, b: 70},\n',
'    font: {family: "Arial"}\n',
'  };\n',
'}\n',
'function groupColorMap(values) {\n',
'  const uniq = [...new Set(values.map(v => String(v)))];\n',
'  const out = {};\n',
'  uniq.forEach((u, i) => out[u] = fixedColors[i % fixedColors.length]);\n',
'  return out;\n',
'}\n',
'function edgeCols() {\n',
'  const a = colBy(["term1","from","source","node1"]); \n',
'  const b = colBy(["term2","to","target","node2","terms"]); \n',
'  const w = colBy(["WCD","wcd","weight","value","count"]); \n',
'  return {a:a,b:b,w:w};\n',
'}\n',
'function renderBar() {\n',
'  const ncs = numericCols();\n',
'  if (ncs.length < 1) { root.append("Bar chart skipped: no numeric column found."); return; }\n',
'  const labelCol = firstTextCol();\n',
'  const yCol = ncs[0];\n',
'  const x = rows.map(r => r[labelCol]);\n',
'  const y = rows.map(r => num(r[yCol]));\n',
'  const d = newDiv("Bar chart");\n',
'  const data = [{type:"bar", x:x, y:y, marker:{color:y, colorscale:"Viridis", showscale:true}}];\n',
'  const layout = transparentLayout("Bar chart: " + yCol + " by " + labelCol);\n',
'  layout.xaxis = {title: labelCol, automargin:true};\n',
'  layout.yaxis = {title: yCol};\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderScatter() {\n',
'  const ncs = numericCols();\n',
'  if (ncs.length < 1) { root.append("Scatter plot skipped: no numeric column found."); return; }\n',
'  const labelCol = firstTextCol();\n',
'  let x, y, xTitle, yTitle;\n',
'  if (ncs.length >= 2) {\n',
'    x = rows.map(r => num(r[ncs[0]])); y = rows.map(r => num(r[ncs[1]])); xTitle = ncs[0]; yTitle = ncs[1];\n',
'  } else {\n',
'    x = rows.map((r,i) => i + 1); y = rows.map(r => num(r[ncs[0]])); xTitle = "Index"; yTitle = ncs[0];\n',
'  }\n',
'  const labels = rows.map(r => labelCol ? r[labelCol] : "");\n',
'  const d = newDiv("Scatter plot");\n',
'  const data = [{type:"scatter", mode:"markers+text", x:x, y:y, text:labels, textposition:"top center", marker:{size:12, color:y, colorscale:"Viridis", showscale:true, line:{color:"#333", width:0.8}}}];\n',
'  const layout = transparentLayout("Scatter plot");\n',
'  layout.xaxis = {title: xTitle};\n',
'  layout.yaxis = {title: yTitle};\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderCirclestackedbarplot() {\n',
'  const individual = colBy(["individual","name","label"]);\n',
'  const group = colBy(["group","cluster","class"]);\n',
'  if (!individual || !group) { root.append("Circle stacked barplot skipped: required columns include individual and group."); return; }\n',
'  const stackCols = cols.filter((c, idx) => idx > 1 && rows.some(r => isNum(r[c])));\n',
'  if (stackCols.length === 0) { root.append("Circle stacked barplot skipped: no stacked numeric columns found."); return; }\n',
'  const clean = rows.filter(r => r[individual] !== null && r[individual] !== undefined && String(r[individual]).trim() !== "");\n',
'  if (clean.length === 0) { root.append("Circle stacked barplot skipped: no usable rows."); return; }\n',
'  const labels = clean.map(r => String(r[individual]));\n',
'  const theta = labels.map((x,i) => 360 * i / labels.length);\n',
'  const d = newDiv("Circle stacked barplot");\n',
'  const traces = stackCols.map((col, i) => ({\n',
'    type: "barpolar",\n',
'    r: clean.map(r => isNum(r[col]) ? num(r[col]) : 0),\n',
'    theta: theta,\n',
'    width: Array(labels.length).fill(360 / labels.length * 0.82),\n',
'    name: col,\n',
'    marker: {color: fixedColors[i % fixedColors.length], opacity: 0.72, line: {color:"#ffffff", width:0.7}},\n',
'    customdata: clean.map(r => [r[individual], r[group], col, isNum(r[col]) ? num(r[col]) : 0]),\n',
'    hovertemplate: "<b>%{customdata[0]}</b><br>Group: %{customdata[1]}<br>Series: %{customdata[2]}<br>Value: %{customdata[3]}<extra></extra>"\n',
'  }));\n',
'  const layout = transparentLayout("Circle stacked barplot");\n',
'  layout.margin = {l:40, r:40, t:60, b:40};\n',
'  layout.showlegend = true;\n',
'  layout.legend = {orientation:"h", x:0.02, y:1.12};\n',
'  layout.barmode = "stack";\n',
'  layout.polar = {\n',
'    bgcolor: "rgba(255,255,255,0)",\n',
'    radialaxis: {visible:true},\n',
'    angularaxis: {tickmode:"array", tickvals:theta, ticktext:labels, direction:"clockwise", rotation:90}\n',
'  };\n',
'  Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderBoxplot() {\n',
'  const groupCol = colBy(["text","group","category","label","name"]);\n',
'  const valueCol = colBy(["value","count","n","score","percent"]);\n',
'  if (!groupCol || !valueCol) { root.append("Box plot skipped: required columns are text,value."); return; }\n',
'  const clean = rows.filter(r => r[groupCol] !== null && r[groupCol] !== undefined && String(r[groupCol]).trim() !== "" && isNum(r[valueCol]));\n',
'  if (clean.length === 0) { root.append("Box plot skipped: no usable rows."); return; }\n',
'  const groups = [...new Set(clean.map(r => String(r[groupCol])) )];\n',
'  const gmap = groupColorMap(groups);\n',
'  const traces = groups.map(g => ({\n',
'    type: "box",\n',
'    name: g,\n',
'    y: clean.filter(r => String(r[groupCol]) === g).map(r => num(r[valueCol])),\n',
'    boxpoints: "all",\n',
'    jitter: 0.35,\n',
'    pointpos: 0,\n',
'    marker: {color: gmap[g], opacity: 0.6, size: 7},\n',
'    line: {color: gmap[g]},\n',
'    fillcolor: gmap[g],\n',
'    opacity: 0.5,\n',
'    hovertemplate: "<b>" + g + "</b><br>Value: %{y}<extra></extra>"\n',
'  }));\n',
'  const d = newDiv("Box plot");\n',
'  const layout = transparentLayout("Box plot");\n',
'  layout.xaxis = {title: groupCol};\n',
'  layout.yaxis = {title: valueCol};\n',
'  layout.showlegend = false;\n',
'  Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderVenn() {\n',
'  const colA = colBy(["countryA","setA","A","left"]);\n',
'  const colB = colBy(["countryB","setB","B","right"]);\n',
'  if (!colA || !colB) { root.append("Venn diagram skipped: required columns are countryA,countryB."); return; }\n',
'  const setA = [...new Set(rows.map(r => r[colA]).filter(v => v !== null && v !== undefined && String(v).trim() !== "").map(v => String(v)))];\n',
'  const setB = [...new Set(rows.map(r => r[colB]).filter(v => v !== null && v !== undefined && String(v).trim() !== "").map(v => String(v)))];\n',
'  const inter = setA.filter(v => setB.includes(v));\n',
'  const onlyA = setA.filter(v => !setB.includes(v));\n',
'  const onlyB = setB.filter(v => !setA.includes(v));\n',
'  const d = newDiv("Venn diagram", true);\n',
'  const width = d.clientWidth || 900; const height = 520;\n',
'  const svg = d3.select(d).append("svg").attr("width", width).attr("height", height).style("background","rgba(255,255,255,0)");\n',
'  svg.append("circle").attr("cx", width*0.42).attr("cy", height*0.52).attr("r", 130).attr("fill", "#0073C2FF").attr("fill-opacity", 0.35).attr("stroke", "#0073C2FF").attr("stroke-width", 2);\n',
'  svg.append("circle").attr("cx", width*0.58).attr("cy", height*0.52).attr("r", 130).attr("fill", "#EFC000FF").attr("fill-opacity", 0.35).attr("stroke", "#EFC000FF").attr("stroke-width", 2);\n',
'  svg.append("text").attr("x", width*0.30).attr("y", height*0.22).attr("text-anchor","middle").style("font-size","22px").style("font-weight","bold").text(colA);\n',
'  svg.append("text").attr("x", width*0.70).attr("y", height*0.22).attr("text-anchor","middle").style("font-size","22px").style("font-weight","bold").text(colB);\n',
'  svg.append("text").attr("x", width*0.34).attr("y", height*0.53).attr("text-anchor","middle").style("font-size","28px").style("font-weight","bold").text(onlyA.length);\n',
'  svg.append("text").attr("x", width*0.50).attr("y", height*0.53).attr("text-anchor","middle").style("font-size","28px").style("font-weight","bold").text(inter.length);\n',
'  svg.append("text").attr("x", width*0.66).attr("y", height*0.53).attr("text-anchor","middle").style("font-size","28px").style("font-weight","bold").text(onlyB.length);\n',
'  const note = document.createElement("div");\n',
'  note.className = "note";\n',
'  note.innerHTML = `<b>${colA}</b> unique items: ${setA.length} &nbsp; | &nbsp; <b>${colB}</b> unique items: ${setB.length} &nbsp; | &nbsp; Intersection: ${inter.length}<br><b>Only ${colA}:</b> ${onlyA.join(", ") || "None"}<br><b>Overlap:</b> ${inter.join(", ") || "None"}<br><b>Only ${colB}:</b> ${onlyB.join(", ") || "None"}`;\n',
'  root.appendChild(note);\n',
'}\n',
'function renderLollipop() {\n',
'  const groupCol = colBy(["group","text","category","label","name"]);\n',
'  const valueCol = colBy(["value","count","n","score","percent"]);\n',
'  if (!groupCol || !valueCol) { root.append("Lollipop chart skipped: required columns are group,value."); return; }\n',
'  const clean = rows.filter(r => r[groupCol] !== null && r[groupCol] !== undefined && String(r[groupCol]).trim() !== "" && isNum(r[valueCol]));\n',
'  if (clean.length === 0) { root.append("Lollipop chart skipped: no usable rows."); return; }\n',
'  const labels = clean.map(r => String(r[groupCol]));\n',
'  const values = clean.map(r => num(r[valueCol]));\n',
'  const maxv = Math.max(...values);\n',
'  const lineTraces = clean.map((r, i) => ({type:"scatter", mode:"lines", x:[0, num(r[valueCol])], y:[String(r[groupCol]), String(r[groupCol])], line:{color:"rgba(120,120,120,0.7)", width:2}, hoverinfo:"skip", showlegend:false}));\n',
'  const pointTrace = {type:"scatter", mode:"markers", x:values, y:labels, marker:{size:12, color:values, colorscale:"Viridis", showscale:true, line:{color:"#1f2937", width:1}}, hovertemplate:"<b>%{y}</b><br>Value: %{x}<extra></extra>", showlegend:false};\n',
'  const d = newDiv("Lollipop chart");\n',
'  const layout = transparentLayout("Lollipop chart");\n',
'  layout.xaxis = {title:valueCol, range:[0, maxv*1.08]};\n',
'  layout.yaxis = {title:groupCol, automargin:true, categoryorder:"array", categoryarray:labels.slice().reverse()};\n',
