'}\n',
'function renderCalendarHeatmap() {\n',
'  const dateCol = colBy(["date","Date","day"]);\n',
'  const valueCol = colBy(["value","VIX.Close","close","Close","count","n"]);\n',
'  if (!dateCol || !valueCol) { root.append("CalendarHeatmap skipped: required columns are date,value."); return; }\n',
'  const clean = rows.map(r => ({date: new Date(r[dateCol]), value: num(r[valueCol])})).filter(d => d.date instanceof Date && !isNaN(d.date) && isFinite(d.value));\n',
'  if (clean.length === 0) { root.append("CalendarHeatmap skipped: no usable rows."); return; }\n',
'  clean.sort((a,b) => a.date - b.date);\n',
'  const minVal = Math.min(...clean.map(d => d.value));\n',
'  const maxVal = Math.max(...clean.map(d => d.value));\n',
'  const months = {};\n',
'  clean.forEach(d => {\n',
'    const y = d.date.getFullYear();\n',
'    const m = d.date.getMonth();\n',
'    const key = y + "-" + String(m + 1).padStart(2, "0");\n',
'    if (!months[key]) months[key] = [];\n',
'    months[key].push(d);\n',
'  });\n',
'  const monthKeys = Object.keys(months).sort();\n',
'  const wrapper = document.createElement("div");\n',
'  wrapper.className = "note";\n',
'  wrapper.innerHTML = "<b>CalendarHeatmap</b>: " + clean.length + " records, range " + minVal.toFixed(2) + " to " + maxVal.toFixed(2) + ".";\n',
'  root.appendChild(wrapper);\n',
'  const host = document.createElement("div");\n',
'  host.style.display = "grid";\n',
'  host.style.gridTemplateColumns = "repeat(auto-fit, minmax(320px, 1fr))";\n',
'  host.style.gap = "18px";\n',
'  root.appendChild(host);\n',
'  const weekdays = ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"];\n',
'  function colorFor(v) {\n',
'    if (!isFinite(v)) return "#f3f4f6";\n',
'    if (maxVal === minVal) return "#34d399";\n',
'    const t = (v - minVal) / (maxVal - minVal);\n',
'    const hue = 120 * t;\n',
'    return `hsl(${hue}, 70%, 55%)`;\n',
'  }\n',
'  monthKeys.forEach(key => {\n',
'    const arr = months[key];\n',
'    const d0 = arr[0].date;\n',
'    const year = d0.getFullYear();\n',
'    const month = d0.getMonth();\n',
'    const monthName = d0.toLocaleString("en-US", {month:"short", year:"numeric"});\n',
'    const first = new Date(year, month, 1);\n',
'    const daysInMonth = new Date(year, month + 1, 0).getDate();\n',
'    const mondayBased = (first.getDay() + 6) % 7;\n',
'    const nWeeks = Math.ceil((mondayBased + daysInMonth) / 7);\n',
'    const card = document.createElement("div");\n',
'    card.style.border = "1px solid #e5e7eb";\n',
'    card.style.borderRadius = "10px";\n',
'    card.style.padding = "10px";\n',
'    card.style.background = "rgba(255,255,255,0.65)";\n',
'    const title = document.createElement("div");\n',
'    title.textContent = monthName;\n',
'    title.style.fontWeight = "700";\n',
'    title.style.marginBottom = "8px";\n',
'    card.appendChild(title);\n',
'    const grid = document.createElement("div");\n',
'    grid.style.display = "grid";\n',
'    grid.style.gridTemplateColumns = "58px repeat(" + nWeeks + ", 1fr)";\n',
'    grid.style.gap = "3px";\n',
'    const blank = document.createElement("div"); blank.textContent = ""; grid.appendChild(blank);\n',
'    for (let w = 1; w <= nWeeks; w++) { const h = document.createElement("div"); h.textContent = w; h.style.textAlign = "center"; h.style.fontSize = "12px"; h.style.fontWeight = "600"; grid.appendChild(h); }\n',
'    const map = {}; arr.forEach(d => { map[d.date.toISOString().slice(0,10)] = d.value; });\n',
'    weekdays.forEach((wd, ridx) => {\n',
'      const lab = document.createElement("div"); lab.textContent = wd; lab.style.fontSize = "12px"; lab.style.fontWeight = "600"; lab.style.display = "flex"; lab.style.alignItems = "center"; grid.appendChild(lab);\n',
'      for (let w = 0; w < nWeeks; w++) {\n',
'        const cell = document.createElement("div");\n',
'        cell.style.minHeight = "34px";\n',
'        cell.style.borderRadius = "4px";\n',
'        cell.style.border = "1px solid #ffffff";\n',
'        cell.style.display = "flex";\n',
'        cell.style.alignItems = "center";\n',
'        cell.style.justifyContent = "center";\n',
'        cell.style.fontSize = "11px";\n',
'        const dayNum = w * 7 + ridx - mondayBased + 1;\n',
'        if (dayNum >= 1 && dayNum <= daysInMonth) {\n',
'          const dt = new Date(year, month, dayNum);\n',
'          const iso = dt.toISOString().slice(0,10);\n',
'          if (Object.prototype.hasOwnProperty.call(map, iso)) {\n',
'            cell.style.background = colorFor(map[iso]);\n',
'            cell.textContent = dayNum;\n',
'            cell.title = iso + ": " + map[iso];\n',
'          } else {\n',
'            cell.style.background = "#f3f4f6";\n',
'            cell.textContent = dayNum;\n',
'            cell.title = iso + ": no data";\n',
'          }\n',
'        } else {\n',
'          cell.style.background = "rgba(0,0,0,0)";\n',
'          cell.style.border = "none";\n',
'        }\n',
'        grid.appendChild(cell);\n',
'      }\n',
'    });\n',
'    card.appendChild(grid);\n',
'    host.appendChild(card);\n',
'  });\n',
'}\n',
'function renderSlopegraph() {\n',
'  const colsAll = cols.slice();\n',
'  if (colsAll.length < 3) { root.append("Slopegraph skipped: requires at least one label column and two numeric columns."); return; }\n',
'  const numericCols = colsAll.filter(c => rows.some(r => isNum(r[c])));\n',
'  const labelCol = colsAll.find(c => !numericCols.includes(c)) || colsAll[0];\n',
'  const timeCols = colsAll.filter(c => c !== labelCol && rows.some(r => isNum(r[c])));\n',
'  if (!labelCol || timeCols.length < 2) { root.append("Slopegraph skipped: requires one label column plus at least two numeric columns."); return; }\n',
'  const clean = rows.filter(r => r[labelCol] !== null && r[labelCol] !== undefined && String(r[labelCol]).trim() !== "" && timeCols.every(tc => isNum(r[tc])));\n',
'  if (clean.length === 0) { root.append("Slopegraph skipped: no usable rows."); return; }\n',
'  const traces = [];\n',
'  const annotations = [];\n',
'  clean.forEach((r, i) => {\n',
'    const name = String(r[labelCol]);\n',
'    const yvals = timeCols.map(tc => num(r[tc]));\n',
'    const lineColor = yvals[yvals.length - 1] >= yvals[0] ? "#0f766e" : "#b91c1c";\n',
'    traces.push({type:"scatter", mode:"lines+markers+text", x:timeCols, y:yvals, name:name, showlegend:false, text:yvals.map(v => Number(v).toFixed(1)), textposition:"top center", textfont:{size:10}, line:{color:lineColor, width:2}, marker:{size:8, color:"#ffffff", line:{color:lineColor, width:2}}, hovertemplate:`<b>${name}</b><br>%{x}: %{y}<extra></extra>`});\n',
'    annotations.push({xref:"paper", yref:"y", x:-0.03, y:yvals[0], text:name, showarrow:false, xanchor:"right", align:"right", font:{size:10, color:"#111827"}});\n',
'    annotations.push({xref:"paper", yref:"y", x:1.03, y:yvals[yvals.length - 1], text:name, showarrow:false, xanchor:"left", align:"left", font:{size:10, color:"#111827"}});\n',
'  });\n',
'  const d = newDiv("Slopegraph");\n',
'  const layout = transparentLayout("Slopegraph");\n',
'  layout.margin = {l:190, r:190, t:60, b:60};\n',
'  layout.xaxis = {title:"", type:"category"};\n',
'  layout.yaxis = {title:"Value", zeroline:false};\n',
'  layout.annotations = annotations;\n',
'  Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
