'}\n',
'function renderBurstLineBox() {\n',
'  const areaCol = colBy(["Area","area","topic","name","label"]);\n',
'  const startCol = colBy(["Start","start","from","begin"]);\n',
'  const endCol = colBy(["End","end","to","finish"]);\n',
'  const countCol = colBy(["Count","count","value","weight","strength"]);\n',
'  if (!areaCol || !startCol || !endCol || !countCol) { root.append("Burst line-box chart skipped: required columns are Area,Start,End,Count."); return; }\n',
'  let clean = rows.filter(r => r[areaCol] !== null && r[areaCol] !== undefined && String(r[areaCol]).trim() !== "" && isNum(r[startCol]) && isNum(r[endCol]) && isNum(r[countCol]))\n',
'    .map(r => ({Area:String(r[areaCol]), Start:num(r[startCol]), End:num(r[endCol]), Count:num(r[countCol])}));\n',
'  if (clean.length === 0) { root.append("Burst line-box chart skipped: no usable rows."); return; }\n',
'  clean.sort((a,b) => a.Start - b.Start || a.End - b.End);\n',
'  const counts = clean.map(d => d.Count);\n',
'  const cmin = Math.min(...counts), cmax = Math.max(...counts);\n',
'  const widthFor = v => (cmax === cmin ? 4 : 1 + (v - cmin) / (cmax - cmin) * 7);\n',
'  const traces = clean.map(d => ({type:"scatter", mode:"lines", x:[d.Start, d.End], y:[d.Area, d.Area], showlegend:false, line:{color:"darkcyan", width:widthFor(d.Count)}, hovertemplate:`<b>${d.Area}</b><br>Start: ${d.Start}<br>End: ${d.End}<br>Count: ${d.Count}<extra></extra>`}));\n',
'  const d = newDiv("Burst line-box chart");\n',
'  const layout = transparentLayout("Burst line-box chart");\n',
'  layout.xaxis = {title:"Year", tickmode:"linear"};\n',
'  layout.yaxis = {title:"Area for Data Burst Strength & Length", automargin:true, categoryorder:"array", categoryarray:clean.map(x => x.Area)};\n',
'  layout.margin = {l:180, r:40, t:60, b:50};\n',
'  Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderTwoPointSlope() {\n',
'  const nameCol = colBy(["name","group","author","label"]);\n',
'  const preCol = colBy(["mean_value_pre","pre","before","start","value_pre"]);\n',
'  const postCol = colBy(["mean_value_post","post","after","end","value_post"]);\n',
'  if (!nameCol || !preCol || !postCol) { root.append("2-point slope graph skipped: required columns are name,mean_value_pre,mean_value_post."); return; }\n',
'  const clean = rows.filter(r => r[nameCol] !== null && r[nameCol] !== undefined && String(r[nameCol]).trim() !== "" && isNum(r[preCol]) && isNum(r[postCol]));\n',
'  if (clean.length === 0) { root.append("2-point slope graph skipped: no usable rows."); return; }\n',
'  const traces = [];\n',
'  const annotations = [];\n',
'  clean.forEach(r => {\n',
'    const name = String(r[nameCol]);\n',
'    const pre = num(r[preCol]);\n',
'    const post = num(r[postCol]);\n',
'    const color = post >= pre ? "#0f766e" : "#b91c1c";\n',
'    traces.push({type:"scatter", mode:"lines+markers+text", x:[preCol, postCol], y:[pre, post], text:[String(pre), String(post)], textposition:"top center", name:name, showlegend:false, line:{color:color, width:2.2}, marker:{size:9, color:"#ffffff", line:{color:color, width:2}}, hovertemplate:`<b>${name}</b><br>%{x}: %{y}<extra></extra>`});\n',
'    annotations.push({xref:"paper", yref:"y", x:-0.04, y:pre, text:name, showarrow:false, xanchor:"right", align:"right", font:{size:10, color:"#111827"}});\n',
'    annotations.push({xref:"paper", yref:"y", x:1.04, y:post, text:name, showarrow:false, xanchor:"left", align:"left", font:{size:10, color:"#111827"}});\n',
'  });\n',
'  const d = newDiv("2-point slope graph");\n',
'  const layout = transparentLayout("2-point slope graph");\n',
'  layout.margin = {l:210, r:210, t:60, b:70};\n',
'  layout.xaxis = {title:"Time point", type:"category"};\n',
'  layout.yaxis = {title:"Value", zeroline:false};\n',
'  layout.annotations = annotations;\n',
'  Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderPubCitationPlot() {\n',
'  const yearCol = colBy(["year","Year"]);\n',
'  const pubCol = colBy(["publication","publications","Publication","Publications","pub","n"]);\n',
'  const citCol = colBy(["citation","citations","Citation","Citations","cite","value"]);\n',
'  if (!yearCol || !citCol) { root.append("Publication/Citation plot skipped: required columns include year and citation/citations."); return; }\n',
'  let summary = [];\n',
'  if (pubCol) {\n',
'    // Summary mode: year,publication,citation\n',
'    summary = rows\n',
'      .filter(r => isNum(r[yearCol]) && isNum(r[pubCol]) && isNum(r[citCol]))\n',
'      .map(r => ({year: num(r[yearCol]), publications: num(r[pubCol]), citations: num(r[citCol])}));\n',
'  } else {\n',
'    // Raw-record mode: citations,year. Publications are counted by year, citations are summed by year.\n',
'    const clean = rows\n',
'      .filter(r => isNum(r[citCol]) && isNum(r[yearCol]))\n',
'      .map(r => ({year: num(r[yearCol]), citations: num(r[citCol])}));\n',
'    const byYear = {};\n',
'    clean.forEach(r => {\n',
'      if (!byYear[r.year]) byYear[r.year] = {year:r.year, publications:0, citations:0};\n',
'      byYear[r.year].publications += 1;\n',
'      byYear[r.year].citations += r.citations;\n',
'    });\n',
'    summary = Object.values(byYear);\n',
'  }\n',
'  summary = summary\n',
'    .filter(d => isFinite(d.year) && isFinite(d.publications) && isFinite(d.citations))\n',
'    .sort((a,b) => a.year - b.year);\n',
'  if (summary.length === 0) { root.append("Publication/Citation plot skipped: no usable rows."); return; }\n',
'  const maxPub = Math.max(...summary.map(d => d.publications));\n',
'  const maxCit = Math.max(...summary.map(d => d.citations));\n',
'  const scaleFactor = maxPub === 0 ? 1 : maxCit / maxPub;\n',
'  const years = summary.map(d => d.year);\n',
'  const d = newDiv("Publication/Citation plot");\n',
'  const data = [\n',
'    {type:"bar", x:years, y:summary.map(d => d.publications), name:"Publications", marker:{color:"rgba(140,140,140,0.65)"}, yaxis:"y", hovertemplate:"Year: %{x}<br>Publications: %{y}<extra></extra>"},\n',
'    {type:"scatter", mode:"lines+markers", x:years, y:summary.map(d => scaleFactor === 0 ? 0 : d.citations / scaleFactor), name:"Citations", yaxis:"y", line:{color:"#b91c1c", width:3}, marker:{color:"#b91c1c", size:8}, customdata:summary.map(d => d.citations), hovertemplate:"Year: %{x}<br>Citations: %{customdata}<extra></extra>"}\n',
'  ];\n',
'  const layout = transparentLayout("Publications and Citations by Year");\n',
'  layout.barmode = "overlay";\n',
'  layout.xaxis = {title:"Year", tickmode:"array", tickvals:years, tickangle:45};\n',
'  layout.yaxis = {title:"Publications", rangemode:"tozero"};\n',
'  layout.yaxis2 = {title:"Citations", overlaying:"y", side:"right", rangemode:"tozero"};\n',
'  layout.legend = {orientation:"h", x:0.35, y:1.12};\n',
'  layout.margin = {l:70, r:80, t:70, b:80};\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderTaipeiMRT() {\n',
'  const srcCol = colBy(["A1","Source","source","from","term1"]);\n',
'  const tgtCol = colBy(["A2","Target","target","to","term2"]);\n',
'  const wCol = colBy(["A3","Weight","weight","WCD","wcd","value"]);\n',
'  const nodeCol = colBy(["A4","Name","name","node","station"]);\n',
'  const sizeCol = colBy(["A5","Publications","publications","size","value2"]);\n',
'  const groupCol = colBy(["A6","Group","group","cluster","line"]);\n',
'  if (!srcCol || !tgtCol) { root.append("Taipei MRT plot skipped: required columns are A1,A2,A3,A4,A5,A6 or Source,Target,Weight,Name,Size,Group."); return; }\n',
'  const edges = rows.filter(r => String(r[srcCol] || "").trim() && String(r[tgtCol] || "").trim()).map(r => ({source:String(r[srcCol]).trim(), target:String(r[tgtCol]).trim(), weight:isNum(r[wCol]) ? num(r[wCol]) : 1})).filter(e => e.source !== e.target);\n',
'  if (!edges.length) { root.append("Taipei MRT plot skipped: no usable edges."); return; }\n',
'  const nodeMap = new Map();\n',
'  function ensureNode(name) { if (!nodeMap.has(name)) nodeMap.set(name, {name:name, size:1, group:1, degree:0}); return nodeMap.get(name); }\n',
'  edges.forEach(e => { ensureNode(e.source).degree += 1; ensureNode(e.target).degree += 1; });\n',
'  if (nodeCol) {\n',
'    rows.forEach(r => {\n',
'      const nm = String(r[nodeCol] || "").trim();\n',
'      if (!nm) return;\n',
'      const nd = ensureNode(nm);\n',
'      if (sizeCol && isNum(r[sizeCol])) nd.size = num(r[sizeCol]);\n',
'      if (groupCol && isNum(r[groupCol])) nd.group = num(r[groupCol]);\n',
'    });\n',
'  }\n',
'  const nodes = Array.from(nodeMap.values());\n',
'  const idx = new Map(nodes.map((n,i) => [n.name, i]));\n',
'  const n = nodes.length;\n',
'  const angleStep = 2 * Math.PI / Math.max(1, n);\n',
'  nodes.forEach((nd, i) => { nd.x = Math.cos(i * angleStep); nd.y = Math.sin(i * angleStep); });\n',
'  for (let iter = 0; iter < 280; iter++) {\n',
'    const fx = Array(n).fill(0), fy = Array(n).fill(0);\n',
'    for (let i = 0; i < n; i++) {\n',
'      for (let j = i + 1; j < n; j++) {\n',
'        let dx = nodes[i].x - nodes[j].x, dy = nodes[i].y - nodes[j].y;\n',
'        let dist2 = dx*dx + dy*dy + 0.01;\n',
'        let f = 0.012 / dist2;\n',
'        fx[i] += dx * f; fy[i] += dy * f;\n',
'        fx[j] -= dx * f; fy[j] -= dy * f;\n',
'      }\n',
'    }\n',
'    edges.forEach(e => {\n',
'      const a = idx.get(e.source), b = idx.get(e.target);\n',
'      if (a == null || b == null) return;\n',
'      let dx = nodes[b].x - nodes[a].x, dy = nodes[b].y - nodes[a].y;\n',
'      let f = 0.016 * (e.weight || 1);\n',
'      fx[a] += dx * f; fy[a] += dy * f;\n',
'      fx[b] -= dx * f; fy[b] -= dy * f;\n',
'    });\n',
'    nodes.forEach((nd, i) => {\n',
'      nd.x += Math.max(-0.04, Math.min(0.04, fx[i]));\n',
'      nd.y += Math.max(-0.04, Math.min(0.04, fy[i]));\n',
'    });\n',
'  }\n',
'  const palette = ["#1f77b4","#d62728","#2ca02c","#9467bd","#ff7f0e","#17becf","#8c564b","#e377c2"];\n',
'  const edgeTraces = edges.map(e => {\n',
'    const a = nodes[idx.get(e.source)], b = nodes[idx.get(e.target)];\n',
'    return {type:"scatter", mode:"lines", x:[a.x,b.x], y:[a.y,b.y], hoverinfo:"text", text:e.source + " → " + e.target + "<br>Weight: " + e.weight, line:{width:Math.max(1, e.weight*3), color:"rgba(70,70,70,0.40)"}, showlegend:false};\n',
'  });\n',
'  const groups = Array.from(new Set(nodes.map(d => d.group))).sort((a,b) => a-b);\n',
'  const nodeTraces = groups.map(g => {\n',
'    const sub = nodes.filter(d => d.group === g);\n',
'    return {type:"scatter", mode:"markers+text", x:sub.map(d=>d.x), y:sub.map(d=>d.y), text:sub.map(d=>d.name), textposition:"top center", textfont:{size:11, color:"#111"}, marker:{size:sub.map(d => 10 + 8 * Math.sqrt(Math.max(0.2, d.size)) + d.degree), color:palette[(Number(g)-1) % palette.length], line:{color:"#ffffff", width:1.5}}, name:"Group " + g, hovertemplate:"Station: %{text}<extra></extra>"};\n',
'  });\n',
'  const d = newDiv("Taipei MRT");\n',
'  const layout = transparentLayout("Taipei MRT Network");\n',
'  layout.xaxis = {visible:false}; layout.yaxis = {visible:false, scaleanchor:"x", scaleratio:1};\n',
'  layout.showlegend = true; layout.legend = {orientation:"h", x:0, y:1.08};\n',
'  layout.margin = {l:10, r:10, t:70, b:10};\n',
'  Plotly.newPlot(d, edgeTraces.concat(nodeTraces), layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderForestPlot() {\n',
'  const estCol = colBy(["Estimate","estimate","effect","Effect","TE","mean"]);\n',
'  const seCol = colBy(["SE","se","stderr","StdErr","standard_error"]);\n',
'  const studyCol = colBy(["Study","study","label","Label","slab","name"]);\n',
'  if (!estCol || !seCol || !studyCol) { root.append("Forest plot skipped: required columns are Estimate, SE, and Study."); return; }\n',
'  const clean = rows\n',
'    .filter(r => isNum(r[estCol]) && isNum(r[seCol]) && String(r[studyCol] || "").trim())\n',
'    .map(r => {\n',
'      const estimate = num(r[estCol]);\n',
'      const se = Math.abs(num(r[seCol]));\n',
'      return {study:String(r[studyCol]).trim(), estimate:estimate, se:se, lower:estimate - 1.96 * se, upper:estimate + 1.96 * se};\n',
'    });\n',
'  if (!clean.length) { root.append("Forest plot skipped: no usable rows."); return; }\n',
'  const yLabels = clean.map(d => d.study).reverse();\n',
'  const xErrPlus = clean.map(d => d.upper - d.estimate).reverse();\n',
'  const xErrMinus = clean.map(d => d.estimate - d.lower).reverse();\n',
'  const estimates = clean.map(d => d.estimate).reverse();\n',
'  const hover = clean.map(d => `${d.study}<br>Estimate: ${d.estimate.toFixed(3)}<br>SE: ${d.se.toFixed(3)}<br>95% CI: ${d.lower.toFixed(3)} to ${d.upper.toFixed(3)}`).reverse();\n',
'  const minX = Math.min(...clean.map(d => d.lower), 0);\n',
'  const maxX = Math.max(...clean.map(d => d.upper), 0);\n',
'  const pad = (maxX - minX || 1) * 0.12;\n',
'  const trace = {\n',
'    type:"scatter", mode:"markers", orientation:"h",\n',
'    x:estimates, y:yLabels, text:hover, hoverinfo:"text",\n',
'    marker:{size:12, color:"#1f2937", symbol:"square", line:{color:"#ffffff", width:1}},\n',
'    error_x:{type:"data", symmetric:false, array:xErrPlus, arrayminus:xErrMinus, color:"#111827", thickness:1.6, width:4},\n',
'    name:"Estimate"\n',
'  };\n',
'  const d = newDiv("Forest plot");\n',
'  const layout = transparentLayout("Forest Plot");\n',
'  layout.xaxis = {title:"Estimate with 95% CI", zeroline:true, zerolinewidth:1.5, zerolinecolor:"#dc2626", range:[minX - pad, maxX + pad]};\n',
'  layout.yaxis = {title:"", automargin:true};\n',
'  layout.margin = {l:140, r:40, t:70, b:70};\n',
'  layout.showlegend = false;\n',
'  layout.height = Math.max(420, 95 + clean.length * 55);\n',
'  Plotly.newPlot(d, [trace], layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderSankeyPlot() {\n',
'  const srcCol = colBy(["source","Source","from","From","A1"]);\n',
'  const tgtCol = colBy(["target","Target","to","To","A2"]);\n',
'  const valCol = colBy(["value","Value","weight","Weight","WCD","wcd","A3"]);\n',
'  const nodeCol = colBy(["node","Node","name","Name","label","Label","A4"]);\n',
'  const groupCol = colBy(["group","Group","NodeGroup","nodeGroup","cluster","A5"]);\n',
'  if (!srcCol || !tgtCol || !valCol) { root.append("Sankey plot skipped: required columns are source,target,value. Optional node,group columns can define node labels and groups."); return; }\n',
'  const rawLinks = rows.filter(r => String(r[srcCol] || "").trim() !== "" && String(r[tgtCol] || "").trim() !== "" && isNum(r[valCol])).map(r => ({sourceRaw:String(r[srcCol]).trim(), targetRaw:String(r[tgtCol]).trim(), value:num(r[valCol])})).filter(d => d.value > 0 && d.sourceRaw !== d.targetRaw);\n',
'  if (!rawLinks.length) { root.append("Sankey plot skipped: no usable links."); return; }\n',
'  const nodeRows = nodeCol ? rows.map((r,i) => ({idx:i, label:String(r[nodeCol] || "").trim(), group: groupCol ? String(r[groupCol] || "").trim() : ""})).filter(d => d.label !== "") : [];\n',
'  const numericValues = rawLinks.map(d => Math.max(Number(d.sourceRaw), Number(d.targetRaw))).filter(v => isFinite(v));\n',
'  const maxIndex = numericValues.length ? Math.max(...numericValues) : -1;\n',
'  const numericMode = nodeRows.length > 0 && rawLinks.every(d => /^\\d+$/.test(d.sourceRaw) && /^\\d+$/.test(d.targetRaw)) && maxIndex < nodeRows.length;\n',
'  let labels = [], groups = [], linkSource = [], linkTarget = [], linkValue = [];\n',
'  if (numericMode) {\n',
'    labels = nodeRows.map((d,i) => d.label);\n',
'    groups = nodeRows.map(d => d.group || "1");\n',
'    rawLinks.forEach(d => { linkSource.push(Number(d.sourceRaw)); linkTarget.push(Number(d.targetRaw)); linkValue.push(d.value); });\n',
'  } else {\n',
'    const map = new Map();\n',
'    function addLabel(x) { if (!map.has(x)) { map.set(x, labels.length); labels.push(x); groups.push("1"); } return map.get(x); }\n',
'    rawLinks.forEach(d => { linkSource.push(addLabel(d.sourceRaw)); linkTarget.push(addLabel(d.targetRaw)); linkValue.push(d.value); });\n',
'  }\n',
'  const palette = ["#1f77b4","#d62728","#2ca02c","#9467bd","#ff7f0e","#17becf","#8c564b","#e377c2","#7f7f7f","#bcbd22"];\n',
'  const nodeColor = groups.map(g => palette[(parseInt(g || "1", 10) - 1 + palette.length) % palette.length]);\n',
'  const d = newDiv("Sankey plot");\n',
'  const trace = {type:"sankey", arrangement:"snap", node:{pad:10, thickness:30, line:{color:"rgba(80,80,80,0.5)", width:0.5}, label:labels, color:nodeColor}, link:{source:linkSource, target:linkTarget, value:linkValue, color:"rgba(120,120,120,0.28)"}};\n',
'  const layout = transparentLayout("Sankey Plot");\n',
'  layout.font = {size:18, color:"red"};\n',
'  layout.height = 680;\n',
'  layout.margin = {l:20, r:20, t:70, b:20};\n',
'  Plotly.newPlot(d, [trace], layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderTamRasch() {\n',
'  const itemCols = cols.filter(c => /^Item\\d+$/i.test(c) || (rows.length > 0 && rows.every(r => String(r[c]).trim() === "" || String(r[c]).trim() === "0" || String(r[c]).trim() === "1")));\n',
'  const nameCol = colBy(["name","Name","student","Student","id","ID"]);\n',
'  const groupCol = colBy(["group","Group","class","Class"]);\n',
'  const items = itemCols.filter(c => ![nameCol, groupCol].includes(c));\n',
'  if (items.length < 2) { root.append("TAM Rasch skipped: required columns are Item1...ItemN plus optional name and group."); return; }\n',
'  const persons = rows.map((r,i) => {\n',
'    const vals = items.map(c => isNum(r[c]) ? num(r[c]) : NaN).filter(v => isFinite(v));\n',
'    const score = vals.reduce((a,b) => a + b, 0);\n',
'    const n = vals.length;\n',
'    const theta = Math.log((score + 0.5) / (n - score + 0.5));\n',
'    return {name: nameCol ? String(r[nameCol]) : ("Person" + (i+1)), group: groupCol ? String(r[groupCol]) : "", score:score, n:n, theta:theta, percent:n ? score/n*100 : 0};\n',
'  }).filter(d => isFinite(d.theta));\n',
'  if (!persons.length) { root.append("TAM Rasch skipped: no usable dichotomous item rows."); return; }\n',
'  persons.sort((a,b) => b.theta - a.theta);\n',
'  const itemStats = items.map(c => {\n',
'    const vals = rows.map(r => isNum(r[c]) ? num(r[c]) : NaN).filter(v => isFinite(v));\n',
'    const p = vals.length ? vals.reduce((a,b)=>a+b,0)/vals.length : 0;\n',
'    const diff = Math.log((1 - p + 0.05) / (p + 0.05));\n',
'    return {item:c, p:p, difficulty:diff};\n',
'  }).sort((a,b) => b.difficulty - a.difficulty);\n',
'  const d1 = newDiv("TAM Rasch person estimates");\n',
'  const personTrace = {type:"bar", orientation:"h", y:persons.map(d=>d.name).reverse(), x:persons.map(d=>d.theta).reverse(), marker:{color:persons.map(d=>d.theta).reverse(), colorscale:"RdBu", showscale:true}, text:persons.map(d=>"Score " + d.score + "/" + d.n + " (" + d.percent.toFixed(1) + "%)").reverse(), hovertemplate:"%{y}<br>Theta approx: %{x:.2f}<br>%{text}<extra></extra>"};\n',
'  const layout1 = transparentLayout("TAM Rasch Approximate Person Ability");\n',
'  layout1.xaxis = {title:"Approximate theta from raw score logit"}; layout1.yaxis = {automargin:true}; layout1.margin = {l:130, r:40, t:70, b:70};\n',
'  Plotly.newPlot(d1, [personTrace], layout1, {responsive:true, displaylogo:false});\n',
'  const d2 = newDiv("TAM Rasch item difficulty");\n',
'  const itemTrace = {type:"bar", orientation:"h", y:itemStats.map(d=>d.item).reverse(), x:itemStats.map(d=>d.difficulty).reverse(), marker:{color:itemStats.map(d=>d.difficulty).reverse(), colorscale:"Viridis", showscale:true}, text:itemStats.map(d=>"p=" + d.p.toFixed(2)).reverse(), hovertemplate:"%{y}<br>Difficulty approx: %{x:.2f}<br>%{text}<extra></extra>"};\n',
'  const layout2 = transparentLayout("TAM Rasch Approximate Item Difficulty");\n',
'  layout2.xaxis = {title:"Approximate item difficulty"}; layout2.yaxis = {automargin:true}; layout2.margin = {l:110, r:40, t:70, b:70};\n',
'  Plotly.newPlot(d2, [itemTrace], layout2, {responsive:true, displaylogo:false});\n',
'  const note = document.createElement("div"); note.className = "note"; note.innerHTML = "<b>TAM Rasch note:</b> This browser plot uses a simple raw-score logit approximation for visualization. For formal TAM estimates, use Custom R mode with library(TAM), tam.mml(), tam.wle(), and tam.eap()."; root.appendChild(note);\n',
'}\n',

'function renderGalleryHistogram() {\n',
'  const valueCol = colBy(["value","Value","score","Score","x"]); const groupCol = colBy(["group","Group","category","Category"]);\n',
'  if (!valueCol) { root.append("R Gallery histogram skipped: requires value column."); return; }\n',
'  const groups = groupCol ? [...new Set(rows.map(r => String(r[groupCol] || "All")))] : ["All"];\n',
'  const traces = groups.map(g => ({type:"histogram", x:rows.filter(r => !groupCol || String(r[groupCol] || "All") === g).map(r => num(r[valueCol])).filter(v=>isFinite(v)), name:g, opacity:0.65}));\n',
'  const d = newDiv("R Gallery: Histogram"); const layout = transparentLayout("Histogram"); layout.barmode = "overlay"; layout.xaxis={title:valueCol}; layout.yaxis={title:"Count"}; Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderGalleryDensity() {\n',
'  const valueCol = colBy(["value","Value","score","Score","x"]); const groupCol = colBy(["group","Group","category","Category"]);\n',
'  if (!valueCol) { root.append("R Gallery density skipped: requires value column."); return; }\n',
'  const groups = groupCol ? [...new Set(rows.map(r => String(r[groupCol] || "All")))] : ["All"];\n',
'  function density(vals) { vals = vals.filter(v=>isFinite(v)); if (!vals.length) return {x:[],y:[]}; const min=Math.min(...vals), max=Math.max(...vals), n=80, bw=(max-min || 1)/8; const xs=Array.from({length:n},(_,i)=>min+(max-min || 1)*i/(n-1)); const ys=xs.map(x=>vals.reduce((a,v)=>a+Math.exp(-0.5*Math.pow((x-v)/bw,2)),0)/(vals.length*bw*Math.sqrt(2*Math.PI))); return {x:xs,y:ys}; }\n',
'  const traces = groups.map(g => { const vals=rows.filter(r => !groupCol || String(r[groupCol] || "All") === g).map(r => num(r[valueCol])); const dd=density(vals); return {type:"scatter", mode:"lines", x:dd.x, y:dd.y, fill:"tozeroy", name:g}; });\n',
'  const d = newDiv("R Gallery: Density"); const layout = transparentLayout("Density plot"); layout.xaxis={title:valueCol}; layout.yaxis={title:"Density"}; Plotly.newPlot(d, traces, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderGalleryViolin() {\n',
