'  const groups=[...new Set(rows.map(r=>String(r[groupCol])) )]; const traces=groups.map(g=>({type:"violin", x:rows.filter(r=>String(r[groupCol])===g).map(r=>g), y:rows.filter(r=>String(r[groupCol])===g).map(r=>num(r[valueCol])), name:g, box:{visible:true}, meanline:{visible:true}}));\n',
'  const d=newDiv("R Gallery: Violin"); const layout=transparentLayout("Violin plot"); layout.xaxis={title:groupCol}; layout.yaxis={title:valueCol}; Plotly.newPlot(d,traces,layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryRidgeline() {\n',
'  const groupCol = colBy(["group","Group","category","Category"]); const valueCol = colBy(["value","Value","score","Score"]); if (!groupCol || !valueCol) { root.append("R Gallery ridgeline skipped: requires group,value."); return; }\n',
'  const groups=[...new Set(rows.map(r=>String(r[groupCol])) )]; function density(vals) { vals=vals.filter(v=>isFinite(v)); const min=Math.min(...vals), max=Math.max(...vals), bw=(max-min||1)/6, xs=Array.from({length:60},(_,i)=>min+(max-min||1)*i/59); const ys=xs.map(x=>vals.reduce((a,v)=>a+Math.exp(-0.5*Math.pow((x-v)/bw,2)),0)/(vals.length*bw*Math.sqrt(2*Math.PI))); return {x:xs,y:ys}; }\n',
'  const traces=groups.map((g,i)=>{ const dd=density(rows.filter(r=>String(r[groupCol])===g).map(r=>num(r[valueCol]))); return {type:"scatter", mode:"lines", x:dd.x, y:dd.y.map(y=>y+i), fill:"tozeroy", name:g}; });\n',
'  const d=newDiv("R Gallery: Ridgeline"); const layout=transparentLayout("Ridgeline-style density"); layout.xaxis={title:valueCol}; layout.yaxis={title:"Group", tickvals:groups.map((g,i)=>i), ticktext:groups}; Plotly.newPlot(d,traces,layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryArea() {\n',
'  const xCol=colBy(["year","Year","x","date"]); const valueCol=colBy(["value","Value","y"]); const groupCol=colBy(["group","Group","category"]); if (!xCol||!valueCol){root.append("R Gallery area skipped: requires year,value and optional group.");return;}\n',
'  const groups=groupCol?[...new Set(rows.map(r=>String(r[groupCol])) )]:["All"]; const traces=groups.map(g=>{const rr=rows.filter(r=>!groupCol||String(r[groupCol])===g); return {type:"scatter",mode:"lines",x:rr.map(r=>r[xCol]),y:rr.map(r=>num(r[valueCol])),fill:"tozeroy",stackgroup:"one",name:g};});\n',
'  const d=newDiv("R Gallery: Area"); const layout=transparentLayout("Area chart"); layout.xaxis={title:xCol}; layout.yaxis={title:valueCol}; Plotly.newPlot(d,traces,layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryStreamgraph() { renderGalleryArea(); }\n',
'function renderGalleryBubble() {\n',
