'  const d=newDiv("R Gallery: Bubble"); const trace={type:"scatter",mode:"markers+text",x:rows.map(r=>num(r[xCol])),y:rows.map(r=>num(r[yCol])),text:labelCol?rows.map(r=>r[labelCol]):undefined,textposition:"top center",marker:{size:rows.map(r=>8+Math.sqrt(Math.max(0,num(r[sizeCol])))*5),color:rows.map((r,i)=>groupCol?i:num(r[sizeCol])),opacity:0.65, line:{color:"#333",width:1}}}; const layout=transparentLayout("Bubble chart"); layout.xaxis={title:xCol}; layout.yaxis={title:yCol}; Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryHeatmap() {\n',
