'  const d=newDiv("R Gallery: Treemap"); const trace={type:"treemap",labels:rows.map(r=>String(r[labelCol])),parents:parentCol?rows.map(r=>String(r[parentCol]||"")):rows.map(r=>""),values:rows.map(r=>num(r[valueCol])),textinfo:"label+value+percent parent"}; const layout=transparentLayout("Treemap"); Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryRadar() {\n',
