'  const groups=[...new Set(rows.map(r=>String(r[groupCol])) )]; const traces=groups.map(g=>{const rr=rows.filter(r=>String(r[groupCol])===g); return {type:"scatterpolar",r:rr.map(r=>num(r[valueCol])),theta:rr.map(r=>String(r[metricCol])),fill:"toself",name:g};}); const d=newDiv("R Gallery: Radar"); const layout=transparentLayout("Radar chart"); layout.polar={radialaxis:{visible:true}}; Plotly.newPlot(d,traces,layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryWaffle() {\n',
'  const categoryCol=colBy(["category","group","label"]); const valueCol=colBy(["value","Value"]); if(!categoryCol||!valueCol){root.append("R Gallery waffle skipped: requires category,value.");return;}\n',
'  const units=[]; rows.forEach((r,i)=>{const n=Math.round(num(r[valueCol])); for(let j=0;j<n;j++) units.push({cat:String(r[categoryCol]), idx:i});}); const x=units.map((d,i)=>i%10), y=units.map((d,i)=>Math.floor(i/10)); const d=newDiv("R Gallery: Waffle"); const trace={type:"scatter",mode:"markers",x:x,y:y,text:units.map(d=>d.cat),marker:{symbol:"square",size:20,color:units.map(d=>d.idx),colorscale:"Portland"},hovertemplate:"%{text}<extra></extra>"}; const layout=transparentLayout("Waffle chart"); layout.xaxis={visible:false}; layout.yaxis={visible:false,scaleanchor:"x"}; Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryWordcloud() {\n',
'  const wordCol=colBy(["word","Word","term","label"]); const freqCol=colBy(["freq","frequency","value","count"]); if(!wordCol||!freqCol){root.append("R Gallery word cloud skipped: requires word,freq.");return;}\n',
'  const d=newDiv("R Gallery: Word cloud", true); const width=d.clientWidth||900, height=560; const svg=d3.select(d).append("svg").attr("width",width).attr("height",height); const maxv=Math.max(...rows.map(r=>num(r[freqCol]))); rows.forEach((r,i)=>{svg.append("text").attr("x",60+(i*97)%Math.max(200,width-120)).attr("y",80+Math.floor(i/6)*70).style("font-size",(12+42*num(r[freqCol])/maxv)+"px").style("font-weight","bold").style("fill",fixedColors[i%fixedColors.length]).text(r[wordCol]);});\n',
'}\n',
'function renderGalleryCorrelogram() { renderGalleryHeatmap(); }\n',
'function renderGalleryDendrogram() {\n',
'  const labelCol=colBy(["label","name"]); const xCol=colBy(["x","X"]); const yCol=colBy(["y","Y"]); if(!labelCol||!xCol||!yCol){root.append("R Gallery dendrogram skipped: requires label,x,y.");return;}\n',
'  const d=newDiv("R Gallery: Dendrogram-style clustering"); const trace={type:"scatter",mode:"markers+text",x:rows.map(r=>num(r[xCol])),y:rows.map(r=>num(r[yCol])),text:rows.map(r=>String(r[labelCol])),textposition:"top center",marker:{size:14,color:rows.map((r,i)=>i),colorscale:"Viridis"}}; const layout=transparentLayout("Dendrogram-style scatter"); layout.xaxis={title:xCol}; layout.yaxis={title:yCol}; Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryJitter() {\n',
'  const groupCol=colBy(["group","Group","category"]); const valueCol=colBy(["value","Value"]); if(!groupCol||!valueCol){root.append("R Gallery jitter skipped: requires group,value.");return;}\n',
'  const x=rows.map(r=>String(r[groupCol])); const y=rows.map(r=>num(r[valueCol])); const d=newDiv("R Gallery: Jitter"); const trace={type:"scatter",mode:"markers",x:x,y:y,marker:{size:10,opacity:0.65}}; const layout=transparentLayout("Jitter plot"); layout.xaxis={title:groupCol}; layout.yaxis={title:valueCol}; Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderGalleryHexbin() {\n',
'  const xCol=colBy(["x","X"]); const yCol=colBy(["y","Y"]); if(!xCol||!yCol){root.append("R Gallery 2D histogram skipped: requires x,y.");return;}\n',
'  const d=newDiv("R Gallery: 2D histogram"); const trace={type:"histogram2d",x:rows.map(r=>num(r[xCol])),y:rows.map(r=>num(r[yCol])),colorscale:"Viridis"}; const layout=transparentLayout("2D histogram"); layout.xaxis={title:xCol}; layout.yaxis={title:yCol}; Plotly.newPlot(d,[trace],layout,{responsive:true,displaylogo:false});\n',
'}\n',
'function renderPyramid() {\n',
'  const ageCol = colBy(["Age","age","Group","group","Label","label"]);\n',
'  const femaleCol = colBy(["Female","female","F","女","女性"]);\n',
'  const maleCol = colBy(["Male","male","M","男","男性"]);\n',
'  if (!ageCol || !femaleCol || !maleCol) { root.append("Pyramid plot skipped: required columns are Age,Female,Male."); return; }\n',
'  const ages = rows.map(r => r[ageCol]);\n',
'  const female = rows.map(r => -Math.abs(num(r[femaleCol])));\n',
'  const male = rows.map(r => Math.abs(num(r[maleCol])));\n',
'  const maxv = Math.max(...female.map(Math.abs), ...male.map(Math.abs));\n',
'  const d = newDiv("Pyramid plot");\n',
'  const data = [\n',
'    {type:"bar", orientation:"h", y:ages, x:female, name:femaleCol, marker:{color:"#d99ad7"}, hovertemplate:femaleCol + ": %{customdata}<br>" + ageCol + ": %{y}<extra></extra>", customdata:female.map(Math.abs)},\n',
'    {type:"bar", orientation:"h", y:ages, x:male, name:maleCol, marker:{color:"#8db7ff"}, hovertemplate:maleCol + ": %{x}<br>" + ageCol + ": %{y}<extra></extra>"}\n',
'  ];\n',
'  const layout = transparentLayout("Pyramid plot: " + femaleCol + " vs " + maleCol);\n',
'  layout.barmode = "relative";\n',
'  layout.xaxis = {range:[-maxv*1.25, maxv*1.25], tickvals:[-maxv, -maxv/2, 0, maxv/2, maxv], ticktext:[String(maxv), String(Math.round(maxv/2)), "0", String(Math.round(maxv/2)), String(maxv)], title:"Value"};\n',
'  layout.yaxis = {title: ageCol, automargin:true};\n',
'  layout.legend = {orientation:"h", x:0.35, y:1.12};\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderNetwork() {\n',
'  const ec = edgeCols();\n',
'  const t1 = ec.a, t2 = ec.b, w = ec.w;\n',
'  if (!t1 || !t2 || !w) { root.append("Network chart skipped: required columns are term1,term2,WCD (or from,to,value)."); return; }\n',
'  const edges = rows.map(r => ({a:String(r[t1]), b:String(r[t2]), w:num(r[w])})).filter(e => e.a && e.b && isFinite(e.w));\n',
'  if (edges.length === 0) { root.append("Network chart skipped: no usable edge rows."); return; }\n',
'  const nodes = [...new Set(edges.flatMap(e => [e.a, e.b]))];\n',
'  const pos = {};\n',
'  nodes.forEach((n,i) => { const ang = 2*Math.PI*i/nodes.length; pos[n] = {x:Math.cos(ang), y:Math.sin(ang)}; });\n',
'  const minW = Math.min(...edges.map(e=>e.w)); const maxW = Math.max(...edges.map(e=>e.w));\n',
'  const edgeTraces = edges.map(e => ({type:"scatter", mode:"lines", x:[pos[e.a].x, pos[e.b].x], y:[pos[e.a].y, pos[e.b].y], hoverinfo:"text", text:e.a + " → " + e.b + "<br>WCD: " + e.w, line:{width:(maxW===minW ? 3 : 1 + 7*(e.w-minW)/(maxW-minW)), color:"rgba(60,60,60,0.55)"}, showlegend:false}));\n',
'  const deg = {}; nodes.forEach(n => deg[n] = 0); edges.forEach(e => { deg[e.a]++; deg[e.b]++; });\n',
'  const nodeTrace = {type:"scatter", mode:"markers+text", x:nodes.map(n=>pos[n].x), y:nodes.map(n=>pos[n].y), text:nodes, textposition:"top center", hovertemplate:"%{text}<extra></extra>", marker:{size:nodes.map(n => 14 + deg[n]*3), color:nodes.map(n => deg[n]), colorscale:"Viridis", showscale:true, line:{color:"#333", width:1}}, showlegend:false};\n',
'  const d = newDiv("Network chart");\n',
'  const layout = transparentLayout("Network chart");\n',
'  layout.xaxis = {visible:false}; layout.yaxis = {visible:false}; layout.margin = {l:20,r:20,t:55,b:20};\n',
'  Plotly.newPlot(d, edgeTraces.concat([nodeTrace]), layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderChord() {\n',
'  const ec = edgeCols();\n',
'  const t1 = ec.a, t2 = ec.b, w = ec.w;\n',
'  if (!t1 || !t2 || !w) { root.append("Chord plot skipped: required columns are from,to,value or term1,term2,WCD."); return; }\n',
'  const edges = rows.map(r => ({a:String(r[t1]), b:String(r[t2]), w:num(r[w])})).filter(e => e.a && e.b && isFinite(e.w));\n',
'  if (edges.length === 0) { root.append("Chord plot skipped: no usable edge rows."); return; }\n',
'  const names = [...new Set(edges.flatMap(e => [e.a, e.b]))];\n',
'  const index = new Map(names.map((n,i)=>[n,i]));\n',
'  const matrix = Array.from({length:names.length}, ()=>Array(names.length).fill(0));\n',
'  edges.forEach(e => { matrix[index.get(e.a)][index.get(e.b)] += e.w; });\n',
'  const d = newDiv("Chord plot", true);\n',
'  const width = d.clientWidth || 900; const height = 720;\n',
'  const outerRadius = Math.min(width, height) * 0.42;\n',
'  const innerRadius = outerRadius - 24;\n',
'  const color = d3.scaleOrdinal().domain(names).range(names.map((n,i)=>fixedColors[i % fixedColors.length]));\n',
'  const svg = d3.select(d).append("svg").attr("width", width).attr("height", height).style("background","rgba(255,255,255,0)");\n',
'  const g = svg.append("g").attr("transform", `translate(${width/2},${height/2})`);\n',
'  const chord = d3.chordDirected().padAngle(0.03).sortSubgroups(d3.descending)(matrix);\n',
'  const arc = d3.arc().innerRadius(innerRadius).outerRadius(outerRadius);\n',
'  const ribbon = d3.ribbonArrow().radius(innerRadius - 1).padAngle(1/innerRadius);\n',
'  g.append("g").selectAll("path").data(chord.groups).join("path")\n',
'    .attr("fill", d => color(names[d.index]))\n',
'    .attr("stroke", d => d3.rgb(color(names[d.index])).darker())\n',
'    .attr("d", arc)\n',
'    .append("title").text(d => names[d.index]);\n',
'  g.append("g").attr("fill-opacity", 0.75).selectAll("path").data(chord).join("path")\n',
'    .attr("d", ribbon)\n',
'    .attr("fill", d => color(names[d.source.index]))\n',
'    .attr("stroke", d => d3.rgb(color(names[d.source.index])).darker())\n',
'    .append("title").text(d => `${names[d.source.index]} → ${names[d.target.index]}: ${d.source.value}`);\n',
'  g.append("g").selectAll("text").data(chord.groups).join("text")\n',
'    .each(d => { d.angle = (d.startAngle + d.endAngle) / 2; })\n',
'    .attr("dy", "0.35em")\n',
'    .attr("transform", d => `rotate(${d.angle * 180 / Math.PI - 90}) translate(${outerRadius + 12}) ${d.angle > Math.PI ? "rotate(180)" : ""}`)\n',
'    .attr("text-anchor", d => d.angle > Math.PI ? "end" : null)\n',
'    .style("font-size", "11px")\n',
'    .text(d => names[d.index]);\n',
'}\n',
'function renderCirclebar() {\n',
'  const individual = colBy(["individual","label","name"]); \n',
'  const group = colBy(["group","cluster","class"]); \n',
'  const value = colBy(["value","count","n","score"]); \n',
'  if (!individual || !group || !value) { root.append("Circlebar chart skipped: required columns are individual,group,value."); return; }\n',
'  const clean = rows.filter(r => r[individual] !== null && r[individual] !== undefined && String(r[individual]).trim() !== "" && isNum(r[value]));\n',
'  if (clean.length === 0) { root.append("Circlebar chart skipped: no usable rows."); return; }\n',
'  const ids = clean.map((r, i) => i + 1);\n',
'  const angles = clean.map((r, i) => 360 * i / clean.length);\n',
'  const labels = clean.map(r => String(r[individual]));\n',
'  const values = clean.map(r => num(r[value]));\n',
'  const groups = clean.map(r => String(r[group]));\n',
'  const gmap = groupColorMap(groups);\n',
'  const colors = groups.map(g => gmap[g]);\n',
'  const d = newDiv("Circlebar chart");\n',
'  const data = [{\n',
'    type: "barpolar",\n',
'    r: values,\n',
'    theta: angles,\n',
'    width: Array(clean.length).fill(360 / clean.length * 0.9),\n',
'    marker: {color: colors, line: {color:"#555", width:0.5}, opacity:0.6},\n',
'    customdata: clean.map(r => [r[individual], r[group], r[value]]),\n',
'    hovertemplate: "<b>%{customdata[0]}</b><br>Group: %{customdata[1]}<br>Value: %{customdata[2]}<extra></extra>",\n',
'    showlegend: false\n',
'  }];\n',
'  const layout = transparentLayout("Circlebar chart");\n',
'  layout.margin = {l:40, r:40, t:60, b:40};\n',
'  layout.polar = {\n',
'    bgcolor: "rgba(255,255,255,0)",\n',
'    radialaxis: {visible:true, range:[0, Math.max(...values) * 1.2]},\n',
'    angularaxis: {tickmode:"array", tickvals:angles, ticktext:labels, direction:"clockwise", rotation:90}\n',
'  };\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderCircularbarplot() {\n',
'  const category = colBy(["category","group","label","name"]);\n',
'  const percent = colBy(["percent","value","count","n"]);\n',
'  if (!category || !percent) { root.append("Circularbarplot skipped: required columns are category,percent."); return; }\n',
'  const clean = rows.filter(r => r[category] !== null && r[category] !== undefined && String(r[category]).trim() !== "" && isNum(r[percent]));\n',
'  if (clean.length === 0) { root.append("Circularbarplot skipped: no usable rows."); return; }\n',
'  const cats = clean.map(r => String(r[category]));\n',
'  const vals = clean.map(r => num(r[percent]));\n',
'  const colors = cats.map((x,i) => fixedColors[i % fixedColors.length]);\n',
'  const theta = cats.map((x,i) => 360 * i / cats.length);\n',
'  const d = newDiv("Circularbarplot");\n',
'  const data = [{\n',
'    type: "barpolar",\n',
'    r: vals,\n',
'    theta: theta,\n',
'    width: Array(cats.length).fill(360 / cats.length * 0.82),\n',
'    marker: {color: colors, line: {color:"#ffffff", width:1}, opacity:0.88},\n',
'    customdata: clean.map(r => [r[category], r[percent]]),\n',
'    hovertemplate: "<b>%{customdata[0]}</b><br>Percent: %{customdata[1]}%<extra></extra>",\n',
'    showlegend: false\n',
'  }];\n',
'  const layout = transparentLayout("Circularbarplot");\n',
'  layout.margin = {l:40, r:40, t:60, b:40};\n',
'  layout.polar = {\n',
'    bgcolor: "rgba(255,255,255,0)",\n',
'    radialaxis: {visible:true, range:[0, Math.max(...vals) * 1.15], ticksuffix:"%"},\n',
'    angularaxis: {tickmode:"array", tickvals:theta, ticktext:cats, direction:"clockwise", rotation:90}\n',
'  };\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'function renderDonut() {\n',
'  const category = colBy(["category","group","label","name"]);\n',
'  const percent = colBy(["percent","value","count","n"]);\n',
'  if (!category || !percent) { root.append("Donut skipped: required columns are category,percent."); return; }\n',
'  const clean = rows.filter(r => r[category] !== null && r[category] !== undefined && String(r[category]).trim() !== "" && isNum(r[percent]));\n',
'  if (clean.length === 0) { root.append("Donut skipped: no usable rows."); return; }\n',
'  const labels = clean.map(r => String(r[category]));\n',
'  const values = clean.map(r => num(r[percent]));\n',
'  const colors = labels.map((x,i) => fixedColors[i % fixedColors.length]);\n',
'  const d = newDiv("Donut");\n',
'  const data = [{\n',
'    type: "pie",\n',
'    labels: labels,\n',
'    values: values,\n',
'    hole: 0.6,\n',
'    textinfo: "label+percent",\n',
'    textposition: "outside",\n',
'    automargin: true,\n',
'    marker: {colors: colors, line: {color:"#ffffff", width:1}},\n',
'    hovertemplate: "<b>%{label}</b><br>Value: %{value}<br>Percent of total: %{percent}<extra></extra>",\n',
'    sort: false,\n',
'    showlegend: false\n',
'  }];\n',
'  const layout = transparentLayout("Donut");\n',
'  layout.showlegend = false;\n',
'  layout.margin = {l:40, r:40, t:60, b:40};\n',
'  Plotly.newPlot(d, data, layout, {responsive:true, displaylogo:false});\n',
'}\n',
'if (selected.length === 0) {\n',
'  root.innerHTML = "<div class=\\"note\\">No plot type selected. Please select at least one checkbox.</div>";\n',
'} else {\n',
'  if (selected.includes("bar")) renderBar();\n',
'  if (selected.includes("scatter")) renderScatter();\n',
'  if (selected.includes("network")) renderNetwork();\n',
'  if (selected.includes("chord")) renderChord();\n',
'  if (selected.includes("circlebar")) renderCirclebar();\n',
'  if (selected.includes("circularbarplot")) renderCircularbarplot();\n',
'  if (selected.includes("donut")) renderDonut();\n',
'  if (selected.includes("circlestackedbarplot")) renderCirclestackedbarplot();\n',
'  if (selected.includes("boxplot")) renderBoxplot();\n',
'  if (selected.includes("venn")) renderVenn();\n',
'  if (selected.includes("lollipop")) renderLollipop();\n',
'  if (selected.includes("calendarheatmap")) renderCalendarHeatmap();\n',
'  if (selected.includes("slopegraph")) renderSlopegraph();\n',
'  if (selected.includes("linechart")) renderLineChart();\n',
'  if (selected.includes("burstlinebox")) renderBurstLineBox();\n',
'  if (selected.includes("twopointslope")) renderTwoPointSlope();\n',
'  if (selected.includes("pubcite")) renderPubCitationPlot();\n',
'  if (selected.includes("taipeimrt")) renderTaipeiMRT();\n',
'  if (selected.includes("forest")) renderForestPlot();\n',
'  if (selected.includes("sankey")) renderSankeyPlot();\n',
'  if (selected.includes("tamrasch")) renderTamRasch();\n',
'  if (selected.includes("gallery_histogram")) renderGalleryHistogram();\n',
'  if (selected.includes("gallery_density")) renderGalleryDensity();\n',
'  if (selected.includes("gallery_violin")) renderGalleryViolin();\n',
'  if (selected.includes("gallery_ridgeline")) renderGalleryRidgeline();\n',
'  if (selected.includes("gallery_area")) renderGalleryArea();\n',
'  if (selected.includes("gallery_streamgraph")) renderGalleryStreamgraph();\n',
'  if (selected.includes("gallery_bubble")) renderGalleryBubble();\n',
'  if (selected.includes("gallery_heatmap")) renderGalleryHeatmap();\n',
'  if (selected.includes("gallery_treemap")) renderGalleryTreemap();\n',
'  if (selected.includes("gallery_radar")) renderGalleryRadar();\n',
'  if (selected.includes("gallery_waffle")) renderGalleryWaffle();\n',
'  if (selected.includes("gallery_wordcloud")) renderGalleryWordcloud();\n',
'  if (selected.includes("gallery_correlogram")) renderGalleryCorrelogram();\n',
'  if (selected.includes("gallery_dendrogram")) renderGalleryDendrogram();\n',
'  if (selected.includes("gallery_jitter")) renderGalleryJitter();\n',
'  if (selected.includes("gallery_hexbin")) renderGalleryHexbin();\n',
'  if (selected.includes("pyramid")) renderPyramid();\n',
'}\n',
'</script>\n',
'</body>\n',
'</html>\n'
  )
}

