          h4("Additional plots: line chart example"),
          tags$p("Paste this CSV into the Additional plots input box and check Line chart. The supported format is one label column followed by multiple numeric columns."),
          tags$pre("country,A2013,A2014,A2015,A2016,A2017,A2018,A2019,A2020,A2021,A2022,A2023,A2024\nU_S,56,56,63,59,64,83,75,92,86,87,87,28\nU_K,16,18,16,12,8,26,5,17,22,12,5,1\nGermany,1,0,3,5,3,7,2,4,10,6,6,0\nCanada,3,3,4,2,1,2,2,2,8,3,6,2\nChina,0,3,1,2,2,3,7,11,0,0,4,0\nAustralia,1,0,0,2,0,0,2,2,1,0,5,0\nDenmark,2,1,2,0,4,2,0,5,0,0,0,0\nAustria,0,0,2,0,6,0,0,3,0,4,0,0\nJapan,2,1,0,2,0,0,0,0,1,0,3,0\nNetherlands,2,0,1,0,2,0,0,0,0,2,1,0\nAAC,4,3.4,5,6.7,8.6,4.6,8.8,7.8,6.4,7.8,9.4,8.8"),

          h4("Additional plots: burst line-box chart example"),
          tags$p("Paste this CSV into the Additional plots input box and check Burst line-box chart. The supported format is Area,Start,End,Count."),
          tags$pre("Area,Start,End,Count\nmHealth,2006,2015,95\nBluetooth,2003,2008,22\nECG,2009,2012,40\nCommunication,2008,2012,38\nMobile_apps,2014,2017,28\nMental_health,2014,2017,26\nBig_data,2014,2017,24\nPatient_engagement,2013,2016,20\nHIV_AIDS,2014,2016,18\nCancer,2014,2016,15\nSustainability,2012,2016,18\nRural_health,2012,2015,16\nHealth_services,2010,2014,20\nWireless_sensor_networks,2009,2012,22\nTAM,2010,2012,15\nHealth_information,2010,2013,18\niOS,2012,2014,14\nHealth_monitoring,2007,2012,25\nEHR,2008,2013,19\nMobile_computing,2004,2010,30"),

          h4("Additional plots: 2-point slope graph example"),
          tags$p("Paste this CSV into the Additional plots input box and check 2-point slope graph."),
          tags$pre("name,mean_value_pre,mean_value_post\nLebwohlMark(U.S),11,28\nBlauveltAndrew(U.S),3.2,5.8\nStroberBruce(U.S),6.4,5.6\nReichKristian(Germany),1.6,3\nGottliebAliceB.(U.S),1,2.8\nBagelJerry(U.S),1.2,2.4\nGuttman-YasskyEmma(U.S),2,2.4\nPappKim(Canada),1.2,1.6\nMenterAlan(U.S),0,0.6"),

          h4("Additional plots: TAM Rasch example"),
          tags$p("Check TAM Rasch and leave the CSV box blank to use the built-in dichotomous item-response example. The browser dashboard shows approximate person ability and item difficulty from raw-score logits. For formal TAM estimates, run the following in Custom R mode:"),
          tags$pre("library(eRm)\nlibrary(ltm)\nlibrary(difR)\nlibrary(TAM)\n\ndata <- data.frame(\n  Item1=c(0,1,1,1,1,1,1,1,0),\n  Item2=c(1,1,1,1,1,1,1,0,1),\n  Item3=c(1,1,1,1,1,1,1,1,0),\n  Item4=c(1,1,1,1,1,1,1,0,1),\n  Item5=c(1,1,1,1,1,1,0,1,0),\n  Item6=c(1,1,1,1,1,0,1,0,0),\n  Item7=c(1,1,0,0,0,1,0,0,0),\n  Item8=c(1,0,1,1,1,0,0,0,0),\n  Item9=c(0,1,0,0,0,0,0,0,0),\n  Item10=c(1,0,0,0,0,0,0,0,0),\n  name=c(\"Student1\",\"Student2\",\"Student3\",\"Student4\",\"Student5\",\"Student6\",\"Student7\",\"Student8\",\"Student9\"),\n  group=c(1,1,1,0,0,1,0,1,0)\n)\n\ndat_1 <- data[, 1:10]\ntam_model <- TAM::tam.mml(dat_1)\nperson_estimates_wle <- TAM::tam.wle(tam_model)\nperson_estimates_eap <- TAM::tam.eap(tam_model)\nprint(person_estimates_wle$theta)\nprint(person_estimates_eap$theta)"),
          h4("Additional plots: Sankey plot example"),
          tags$p("Check Sankey plot and leave the CSV box blank to use the built-in example. CSV format: source,target,value,node,group. If source and target are zero-based numeric indices, node and group provide node labels and groups. If source and target are names, node/group are optional."),
          tags$pre("source,target,value,node,group\n0,1,124.73,Agricultural,1\n1,2,0.6,Bio-conversion,2\n1,3,26.86,Liquid,3"),
          h4("Additional plots: Forest plot example"),
          tags$p("Check Forest plot and leave the CSV box blank to use the built-in example. CSV format: Estimate,SE,Study. The app calculates 95% CI as Estimate ± 1.96 × SE and renders the plot in HTML without calling forest()."),
          tags$pre("Estimate,SE,Study\n0.2,0.1,Study1\n0.5,0.15,Study2\n0.3,0.2,Study3"),
          h4("Additional plots: Taipei MRT example"),
          tags$p("Check Taipei MRT and leave the CSV box blank to use the built-in Taipei MRT example. CSV format: A1,A2,A3,A4,A5,A6, where A1-A3 are Source, Target, Weight and A4-A6 are station Name, node size, and group/line."),
          h4("Additional plots: Publication/Citation plot example"),
          tags$p("Paste this CSV into the Additional plots input box and check Publication/Citation plot. Preferred format is year,publication,citation. The app also accepts raw citations,year records and then computes publications by counting rows per year and citations by summing citations per year."),
          tags$pre("year,publication,citation\n2013,2,17\n2014,3,43\n2015,4,65\n2016,4,81\n2017,5,121\n2018,5,139\n2019,5,163\n2020,5,201\n2021,5,241\n2022,5,270\n2023,5,323\n2024,5,375"),
          h4("Alternative raw Publication/Citation input"),
          tags$p("If only citations and year are available, use citations,year. Publications will be computed as the number of rows in each year."),
          tags$pre("citations,year\n12,2013\n5,2013\n20,2014\n8,2014\n15,2014\n32,2015\n10,2015\n5,2015\n18,2015"),

          h4("Equivalent R/ggplot2 box-plot code"),
          tags$pre("library(ggplot2)\n\ndata <- data.frame(\n  text = c(\"A\",\"B\",\"B\",\"C\",\"A\",\"B\",\"D\",\"D\",\"A\",\"A\",\"B\",\"A\",\"C\",\"A\",\"A\",\"A\",\"B\",\"A\",\"B\",\"A\"),\n  value = c(1927.72,665.44,525.93,478.59,459.51,420.35,348.37,178.03,175.9,150.18,147.29,132.96,125.5,124.85,114.3,103.5,82.88,79.62,76.44,72.59)\n)\n\nggplot(data, aes(x = text, y = value, fill = text)) +\n  geom_boxplot()"),

          h4("Equivalent R/ggplot2 bar-chart code"),
          tags$pre("library(ggplot2)\n\ndata <- data.frame(\n  group = c(\"China\",\"U.S\",\"Japan\",\"South K\",\"Germany\",\"Turkey\",\"Canada\",\"India\",\"Netherl\",\"Taiwan\",\"France\",\"Italy\",\"Iran\",\"Spain\",\"Thailan\",\"Switzer\",\"Denmark\",\"Poland\",\"Egypt\",\"Sweden\"),\n  value = c(3567.59,2590.93,605.75,569.81,319.17,253.78,174.06,151.54,124.89,103.66,95.34,75.03,69.05,61.18,50.57,48.69,34.76,33.24,28.3,26.08)\n)\n\n# vertical bar chart\nggplot(data, aes(x = group, y = value)) +\n  geom_bar(stat = \"identity\", width = 0.8)\n\n# horizontal bar chart\nggplot(data, aes(x = group, y = value)) +\n  geom_bar(stat = \"identity\") +\n  coord_flip()"),

          h4("Cluster colors"),
          tags$p("Clusters 1 to 8 use fixed colors: red, blue, yellow, green, purple, pink, black, and light blue. Additional clusters receive generated colors automatically.")
        )
      )
    )
  )
)

server <- function(input, output, session) {
  observeEvent(input$run, {
    updateTabsetPanel(session, "map_tabs", selected = "Taiwan map")
  }, ignoreInit = TRUE)

  observeEvent(input$run_world, {
    updateTabsetPanel(session, "map_tabs", selected = "World map")
  }, ignoreInit = TRUE)

  observeEvent(input$run_us, {
    updateTabsetPanel(session, "map_tabs", selected = "US map")
  }, ignoreInit = TRUE)

  observeEvent(input$run_china, {
    updateTabsetPanel(session, "map_tabs", selected = "China map")
  }, ignoreInit = TRUE)

  # Separate the two plot-generation buttons explicitly.
  # Left-side button = Additional plots from CSV/built-in examples.
  # Right-side button = pasted Custom R code only.
  plot_run_source <- reactiveVal("additional")
  plot_run_nonce <- reactiveVal(0)

  observeEvent(input$run_plots, {
    plot_run_source("additional")
    plot_run_nonce(plot_run_nonce() + 1)
    updateCheckboxInput(session, "plot_custom_r", value = FALSE)
    updateTabsetPanel(session, "map_tabs", selected = "Plots")
  }, ignoreInit = TRUE)

  observeEvent(input$run_plots_r_code, {
    plot_run_source("custom")
    plot_run_nonce(plot_run_nonce() + 1)
    updateCheckboxInput(session, "plot_custom_r", value = TRUE)
    updateTabsetPanel(session, "map_tabs", selected = "Plots")
  }, ignoreInit = TRUE)

  observeEvent(input$clean_plot_data, {
    updateTextAreaInput(session, "plot_txt", value = "")
    updateCheckboxInput(session, "plot_bar", value = FALSE)
    updateCheckboxInput(session, "plot_scatter", value = FALSE)
    updateCheckboxInput(session, "plot_network", value = FALSE)
    updateCheckboxInput(session, "plot_chord", value = FALSE)
    updateCheckboxInput(session, "plot_circlebar", value = FALSE)
    updateCheckboxInput(session, "plot_circularbarplot", value = FALSE)
    updateCheckboxInput(session, "plot_donut", value = FALSE)
    updateCheckboxInput(session, "plot_circlestackedbarplot", value = FALSE)
    updateCheckboxInput(session, "plot_boxplot", value = FALSE)
    updateCheckboxInput(session, "plot_venn", value = FALSE)
    updateCheckboxInput(session, "plot_lollipop", value = FALSE)
    updateCheckboxInput(session, "plot_calendarheatmap", value = FALSE)
    updateCheckboxInput(session, "plot_slopegraph", value = FALSE)
    updateCheckboxInput(session, "plot_linechart", value = FALSE)
    updateCheckboxInput(session, "plot_burstlinebox", value = FALSE)
    updateCheckboxInput(session, "plot_twopointslope", value = FALSE)
    updateCheckboxInput(session, "plot_pubcite", value = FALSE)
    updateCheckboxInput(session, "plot_taipeimrt", value = FALSE)
    updateCheckboxInput(session, "plot_forest", value = FALSE)
    updateCheckboxInput(session, "plot_sankey", value = FALSE)
    updateCheckboxInput(session, "plot_tamrasch", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_histogram", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_density", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_violin", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_ridgeline", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_area", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_streamgraph", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_bubble", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_heatmap", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_treemap", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_radar", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_waffle", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_wordcloud", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_correlogram", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_dendrogram", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_jitter", value = FALSE)
    updateCheckboxInput(session, "plot_gallery_hexbin", value = FALSE)
    updateCheckboxInput(session, "plot_pyramid", value = FALSE)
    updateTabsetPanel(session, "map_tabs", selected = "Plots")
  }, ignoreInit = TRUE)

  observeEvent(input$clean_r_code, {
    updateTextAreaInput(session, "plot_r_code", value = "")
    updateNumericInput(session, "custom_r_font_size", value = 22)
    updateCheckboxInput(session, "plot_custom_r", value = FALSE)
    updateTabsetPanel(session, "map_tabs", selected = "Plots")
  }, ignoreInit = TRUE)

  processed <- eventReactive(input$run, {
    df <- parse_taiwan_input(input$txt)
    df <- validate_and_order(df)
    df <- add_asp_colors(df, input$min_col, input$max_col)

    list(
      data = df,
      gini = compute_group_gini(df$value, groups = 5),
      aac_info = compute_aac_top3(df),
      top1 = paste(df$name[df$value == max(df$value)], collapse = ", "),
      bottom1 = paste(df$name[df$value == min(df$value)], collapse = ", "),
      value_string = paste(df$value, collapse = ","),
      city_string = paste(df$name, collapse = ","),
      color_string = paste(df$kcolor_no_hash, collapse = ","),
      api_key = if (nzchar(trimws(input$google_key))) trimws(input$google_key) else DEFAULT_GOOGLE_API_KEY
    )
  }, ignoreInit = FALSE)

  world_processed <- eventReactive(input$run_world, {
    df <- parse_world_input(input$world_txt)
    stats <- compute_general_stats(df, name_col = "country_original", value_col = "count")
    world_mode <- attr(df, "world_mode")
    if (is.null(world_mode)) world_mode <- if (all(is.na(df$cluster))) "choropleth" else "bubble"

    edge_df <- data.frame()
    relation_effective <- FALSE

    html_out <- if (identical(world_mode, "bubble")) {
      relation_effective <- isTRUE(input$world_show_relations)
      if (relation_effective) {
        edge_df <- parse_world_edges(input$world_relation_txt, df, enabled = TRUE)
      }
      make_world_bubble_html(df, stats, input$world_min_col, input$world_max_col, edge_df)
    } else {
      make_world_geo_html(df, stats, input$world_min_col, input$world_max_col, if (nzchar(trimws(input$google_key))) trimws(input$google_key) else DEFAULT_GOOGLE_API_KEY)
    }

    list(
      data = df,
      stats = stats,
      world_mode = world_mode,
      relation_effective = relation_effective,
      edges = edge_df,
      html = html_out
    )
  }, ignoreInit = FALSE)

  us_processed <- eventReactive(input$run_us, {
    df <- parse_us_input(input$us_txt)
    stats <- compute_general_stats(df, name_col = "state", value_col = "value")

    list(
      data = df,
      stats = stats,
      html = make_us_plotly_html(df, stats, input$us_min_col, input$us_max_col)
    )
  }, ignoreInit = FALSE)

  china_processed <- eventReactive(input$run_china, {
    df <- parse_china_input(input$china_txt)
    stats <- compute_general_stats(df, name_col = "name", value_col = "value")

    list(
      data = df,
      stats = stats,
      html = make_china_echarts_html(df, stats, input$china_min_col, input$china_max_col)
    )
  }, ignoreInit = FALSE)

  plots_processed <- eventReactive(plot_run_nonce(), {
    run_source <- plot_run_source()

    if (identical(run_source, "custom")) {
      # Custom R mode:
      # Ignore the CSV input box and all built-in plot checkboxes.
      # Only the pasted R script is executed when the right-side Generate plot button is clicked.
      df <- data.frame()
      html_out <- make_plots_html(df, "__custom_r__")
      custom_fragment <- make_custom_r_plot_html(input$plot_r_code, input$custom_r_font_size)
      html_out <- insert_custom_fragment(html_out, custom_fragment)

      return(list(
        data = df,
        selected = "custom_r",
        default_used = FALSE,
        custom_r_used = TRUE,
        html = html_out
      ))
    }

    selected <- c()
    if (isTRUE(input$plot_bar)) selected <- c(selected, "bar")
    if (isTRUE(input$plot_scatter)) selected <- c(selected, "scatter")
    if (isTRUE(input$plot_network)) selected <- c(selected, "network")
    if (isTRUE(input$plot_chord)) selected <- c(selected, "chord")
    if (isTRUE(input$plot_circlebar)) selected <- c(selected, "circlebar")
    if (isTRUE(input$plot_circularbarplot)) selected <- c(selected, "circularbarplot")
    if (isTRUE(input$plot_donut)) selected <- c(selected, "donut")
    if (isTRUE(input$plot_circlestackedbarplot)) selected <- c(selected, "circlestackedbarplot")
    if (isTRUE(input$plot_boxplot)) selected <- c(selected, "boxplot")
    if (isTRUE(input$plot_venn)) selected <- c(selected, "venn")
    if (isTRUE(input$plot_lollipop)) selected <- c(selected, "lollipop")
    if (isTRUE(input$plot_calendarheatmap)) selected <- c(selected, "calendarheatmap")
    if (isTRUE(input$plot_slopegraph)) selected <- c(selected, "slopegraph")
    if (isTRUE(input$plot_linechart)) selected <- c(selected, "linechart")
    if (isTRUE(input$plot_burstlinebox)) selected <- c(selected, "burstlinebox")
    if (isTRUE(input$plot_twopointslope)) selected <- c(selected, "twopointslope")
    if (isTRUE(input$plot_pubcite)) selected <- c(selected, "pubcite")
    if (isTRUE(input$plot_taipeimrt)) selected <- c(selected, "taipeimrt")
    if (isTRUE(input$plot_forest)) selected <- c(selected, "forest")
    if (isTRUE(input$plot_sankey)) selected <- c(selected, "sankey")
    if (isTRUE(input$plot_tamrasch)) selected <- c(selected, "tamrasch")
    if (isTRUE(input$plot_gallery_histogram)) selected <- c(selected, "gallery_histogram")
    if (isTRUE(input$plot_gallery_density)) selected <- c(selected, "gallery_density")
    if (isTRUE(input$plot_gallery_violin)) selected <- c(selected, "gallery_violin")
    if (isTRUE(input$plot_gallery_ridgeline)) selected <- c(selected, "gallery_ridgeline")
    if (isTRUE(input$plot_gallery_area)) selected <- c(selected, "gallery_area")
    if (isTRUE(input$plot_gallery_streamgraph)) selected <- c(selected, "gallery_streamgraph")
    if (isTRUE(input$plot_gallery_bubble)) selected <- c(selected, "gallery_bubble")
    if (isTRUE(input$plot_gallery_heatmap)) selected <- c(selected, "gallery_heatmap")
    if (isTRUE(input$plot_gallery_treemap)) selected <- c(selected, "gallery_treemap")
    if (isTRUE(input$plot_gallery_radar)) selected <- c(selected, "gallery_radar")
    if (isTRUE(input$plot_gallery_waffle)) selected <- c(selected, "gallery_waffle")
    if (isTRUE(input$plot_gallery_wordcloud)) selected <- c(selected, "gallery_wordcloud")
    if (isTRUE(input$plot_gallery_correlogram)) selected <- c(selected, "gallery_correlogram")
    if (isTRUE(input$plot_gallery_dendrogram)) selected <- c(selected, "gallery_dendrogram")
    if (isTRUE(input$plot_gallery_jitter)) selected <- c(selected, "gallery_jitter")
    if (isTRUE(input$plot_gallery_hexbin)) selected <- c(selected, "gallery_hexbin")
    if (isTRUE(input$plot_pyramid)) selected <- c(selected, "pyramid")

    default_used <- !nzchar(trimws(input$plot_txt))
    plot_source <- if (default_used) choose_plot_default_text(selected) else input$plot_txt

    if (default_used) {
      updateTextAreaInput(session, "plot_txt", value = plot_source)
    }

    df <- parse_plot_input(plot_source)
    html_out <- make_plots_html(df, selected)

    list(
      data = df,
      selected = selected,
      default_used = default_used,
      custom_r_used = FALSE,
      html = html_out
    )
  }, ignoreInit = FALSE)

  generated_html <- reactive({
    p <- processed()
    make_google_map_html(p$data, p$api_key, asp_polygon_json)
  })

  world_generated_html <- reactive({
    world_processed()$html
  })

  us_generated_html <- reactive({
    us_processed()$html
  })

  china_generated_html <- reactive({
    china_processed()$html
  })

  plots_generated_html <- reactive({
    plots_processed()$html
  })

  output$message <- renderText({
    p <- try(processed(), silent = TRUE)
    w <- try(world_processed(), silent = TRUE)

    tw_msg <- if (inherits(p, "try-error")) {
      paste("Taiwan input error:", conditionMessage(attr(p, "condition")))
    } else {
      key_msg <- if (nzchar(trimws(input$google_key))) "user Google key" else "default Google key"
      paste0("Taiwan map ready: 22 counties/cities, 40 ASP polygon tracks; using ", key_msg, ".")
    }

    w_msg <- if (inherits(w, "try-error")) {
      paste("World input error:", conditionMessage(attr(w, "condition")))
    } else {
      rel_msg <- if (isTRUE(w$relation_effective)) paste0("; relation curves: ", nrow(w$edges)) else ""
      paste0("World map ready: ", nrow(w$data), " countries/regions parsed; mode: ", w$world_mode, rel_msg, ".")
    }

    u <- try(us_processed(), silent = TRUE)
    u_msg <- if (inherits(u, "try-error")) {
      paste("US input error:", conditionMessage(attr(u, "condition")))
    } else {
      paste0("US map ready: ", nrow(u$data), " states parsed.")
    }

    c1 <- try(china_processed(), silent = TRUE)
    c_msg <- if (inherits(c1, "try-error")) {
      paste("China input error:", conditionMessage(attr(c1, "condition")))
    } else {
      paste0("China map ready: ", nrow(c1$data), " regions parsed.")
    }

    pl <- try(plots_processed(), silent = TRUE)
    pl_msg <- if (inherits(pl, "try-error")) {
      paste("Plots input error:", conditionMessage(attr(pl, "condition")))
    } else {
      source_msg <- if (isTRUE(pl$default_used)) "built-in default data" else "user input data"
      paste0("Plots ready: ", paste(pl$selected, collapse = ", "), "; source: ", source_msg, ".")
    }

    paste(tw_msg, w_msg, u_msg, c_msg, pl_msg, sep = "\n")
  })

